import mysql from 'mysql2/promise';
import { config } from 'dotenv';
config({ path: '.env.local' });

// ============================================================
// MODULE QUIZ QUESTIONS - 10 per module (expert level, English)
// ============================================================
const moduleQuestions = [
  // ─── EPF Course ───────────────────────────────────────────
  // Module 10001 - Introduction to Oil & Gas Industry
  ...[
    { q: "A reservoir with an API gravity of 28° is classified as:", opts: ["Light crude oil","Medium crude oil","Heavy crude oil","Extra-heavy crude oil"], ans: 1, exp: "API gravity 22–31.1° = medium crude. Light crude >31.1°, heavy crude <22°, extra-heavy <10°." },
    { q: "Which upstream activity directly precedes the drilling phase in field development?", opts: ["Reservoir simulation","Seismic acquisition and interpretation","Production testing","Pipeline construction"], ans: 1, exp: "Seismic surveys are used to identify subsurface structures before drilling exploration wells." },
    { q: "In a gas condensate reservoir, retrograde condensation occurs when:", opts: ["Pressure increases above the dew point","Pressure drops below the dew point during production","Temperature exceeds the critical temperature","Water influx dilutes the gas phase"], ans: 1, exp: "Retrograde condensation is the unusual phenomenon where liquid forms as pressure DROPS below the dew point in a gas condensate reservoir." },
    { q: "The Hubbert Peak Theory predicts that oil production from any region follows:", opts: ["An exponential growth curve","A bell-shaped curve with a production peak","A linear decline after discovery","A plateau followed by sudden collapse"], ans: 1, exp: "M. King Hubbert's model predicts oil production follows a bell-shaped (logistic) curve, peaking when roughly half the recoverable reserves are depleted." },
    { q: "Which fiscal regime gives the host government the highest share of production when oil prices are high?", opts: ["Royalty/Tax system","Production Sharing Contract (PSC)","Service contract","Joint venture"], ans: 1, exp: "In a PSC, the government's profit oil share typically increases with higher oil prices through sliding-scale mechanisms, often resulting in a higher government take than fixed royalty/tax systems." },
    { q: "A field has STOIIP of 500 MMbbl with a recovery factor of 35%. If 120 MMbbl has been produced, what is the remaining recoverable reserve?", opts: ["175 MMbbl","55 MMbbl","380 MMbbl","130 MMbbl"], ans: 1, exp: "Total recoverable = 500 × 0.35 = 175 MMbbl. Remaining = 175 - 120 = 55 MMbbl." },
    { q: "The primary difference between 2P and 3P reserves classification is:", opts: ["2P includes proved + probable; 3P adds possible reserves","2P is for gas only; 3P includes oil and gas","2P uses deterministic methods; 3P uses probabilistic","2P is certified by regulators; 3P is internal estimates"], ans: 0, exp: "Under SPE-PRMS: 1P=Proved, 2P=Proved+Probable, 3P=Proved+Probable+Possible reserves." },
    { q: "Which downstream process converts heavy fuel oil fractions into lighter, more valuable products?", opts: ["Atmospheric distillation","Catalytic cracking (FCC)","Desalting","Crude blending"], ans: 1, exp: "Fluid Catalytic Cracking (FCC) is a secondary refining process that converts heavy gas oils and residues into lighter products like gasoline and LPG." },
    { q: "In a PSA (Production Sharing Agreement), 'cost oil' refers to:", opts: ["Oil sold to cover operating costs","The portion of production used to recover capital and operating costs","Oil retained by the contractor as profit","Oil produced during the exploration phase"], ans: 1, exp: "Cost oil is the portion of production allocated to the contractor to recover their capital expenditure (capex) and operating expenditure (opex) before profit oil is split." },
    { q: "The netback value of crude oil is calculated as:", opts: ["Wellhead price minus royalties","Realized product prices minus refining costs, transportation, and marketing expenses","Spot price minus quality differential","FOB price minus freight costs"], ans: 1, exp: "Netback = sum of (product yield × product price) - refining costs - transportation - marketing. It represents the value of crude to the refiner working backward from product prices." },
  ].map((q, i) => ({ moduleId: 10001, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 10002 - EPF Concept and Role
  ...[
    { q: "The primary technical justification for deploying an EPF instead of waiting for a permanent CPF is:", opts: ["Lower capital cost per barrel","Accelerated first oil to generate early cash flow and fund full-field development","Simpler regulatory approval process","Reduced environmental footprint"], ans: 1, exp: "EPFs enable early monetization of discovered reserves, generating cash flow that can fund the larger CPF investment, reducing the overall project financing burden." },
    { q: "An EPF typically handles what percentage of the field's ultimate plateau production rate?", opts: ["5–10%","15–30%","50–70%","80–100%"], ans: 1, exp: "EPFs are typically designed for 15–30% of the field's ultimate production rate, sufficient for early cash flow without the full infrastructure investment." },
    { q: "Which of the following is NOT a typical design criterion for an EPF?", opts: ["Modular construction for rapid deployment","Designed for 3–7 year operational life","Full NGL extraction capability","Ability to be relocated or expanded"], ans: 2, exp: "Full NGL extraction is typically a feature of permanent CPFs. EPFs focus on basic oil/gas/water separation and stabilization, not complex NGL recovery." },
    { q: "In EPF design, the 'design envelope' concept means:", opts: ["The physical boundary of the facility","Designing for a range of fluid compositions and flow rates to handle reservoir uncertainty","The maximum pressure rating of vessels","The plot plan boundary for safety exclusion zones"], ans: 1, exp: "The design envelope accounts for uncertainty in reservoir performance by designing equipment to handle a range of GOR, water cut, and flow rate scenarios." },
    { q: "A brownfield EPF differs from a greenfield EPF primarily in:", opts: ["Processing capacity","Integration with existing infrastructure and tie-in complexity","Ownership structure","Regulatory requirements"], ans: 1, exp: "Brownfield EPFs must integrate with existing pipelines, utilities, and processing facilities, adding complexity to tie-ins, interface management, and simultaneous operations (SIMOPS)." },
    { q: "The 'stranded gas' problem in early production is typically addressed by:", opts: ["Flaring all associated gas","Installing a small gas compression and export system or reinjection","Shutting in high-GOR wells","Converting gas to LNG immediately"], ans: 1, exp: "EPFs typically include gas compression for export or reinjection to avoid flaring (regulatory and environmental constraints) and to maintain reservoir pressure." },
    { q: "Which EPF configuration is most appropriate for a remote onshore location with no pipeline infrastructure?", opts: ["Truck-mounted mobile processing unit","Floating Production Storage and Offloading (FPSO)","Conventional fixed platform","Subsea processing system"], ans: 0, exp: "Truck-mounted or skid-mounted mobile processing units are ideal for remote onshore locations without pipeline infrastructure, allowing crude to be trucked to market." },
    { q: "The 'plateau rate' in EPF design is typically limited by:", opts: ["Reservoir deliverability only","The installed processing capacity and wellhead compression","Pipeline export capacity only","Regulatory production limits only"], ans: 1, exp: "Plateau rate is constrained by both reservoir deliverability AND installed processing capacity. The EPF design must balance these to optimize production." },
    { q: "What is the main risk of designing an EPF with insufficient water handling capacity?", opts: ["Increased gas flaring","Production deferment as water cut rises, requiring costly upgrades","Higher crude oil viscosity","Increased H2S content in produced gas"], ans: 1, exp: "Water cut typically increases over field life. Insufficient water handling capacity forces production deferment when water cut exceeds design limits, requiring costly debottlenecking." },
    { q: "In EPF economics, the 'breakeven oil price' calculation must include:", opts: ["Only OPEX costs","CAPEX amortization, OPEX, royalties, and taxes over the EPF operational life","Only CAPEX costs","Market price differentials only"], ans: 1, exp: "Breakeven price = (Total CAPEX + Total OPEX + Royalties + Taxes) / Total production over EPF life. All cost components must be included for accurate economic evaluation." },
  ].map((q, i) => ({ moduleId: 10002, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 10003 - Fluid Properties and Phase Behavior
  ...[
    { q: "A crude oil sample has a specific gravity of 0.876. What is its API gravity?", opts: ["28.7°","30.1°","26.4°","32.5°"], ans: 0, exp: "API = (141.5/SG) - 131.5 = (141.5/0.876) - 131.5 = 161.53 - 131.5 = 30.03°. Closest answer is 30.1°. Wait - let me recalculate: 141.5/0.876 = 161.53, 161.53-131.5 = 30.03. The answer is 30.1°." },
    { q: "At reservoir conditions, a gas condensate system exists as a single-phase gas. What happens when pressure drops below the dew point during production?", opts: ["The gas expands and remains single phase","Liquid condensate forms in the reservoir (retrograde condensation)","The gas converts entirely to liquid","Water vaporizes into the gas phase"], ans: 1, exp: "Below the dew point, retrograde condensation occurs - liquid drops out in the reservoir. This condensate is often unrecoverable, representing a significant loss of valuable C5+ hydrocarbons." },
    { q: "The Z-factor (compressibility factor) for a real gas at high pressure and high temperature compared to ideal gas behavior:", opts: ["Is always greater than 1.0","Can be less than 1.0 at moderate pressures and greater than 1.0 at very high pressures","Is always less than 1.0","Equals 1.0 at all conditions"], ans: 1, exp: "Z-factor behavior: at moderate pressures, intermolecular attractions dominate (Z<1); at very high pressures, molecular volume effects dominate (Z>1). Z=1 only for ideal gas." },
    { q: "Which correlation is most appropriate for calculating oil viscosity at reservoir conditions?", opts: ["Beggs and Robinson correlation","Darcy's law","Klinkenberg correlation","van der Waals equation"], ans: 0, exp: "Beggs and Robinson (1975) is the most widely used empirical correlation for dead oil viscosity, with subsequent correlations for saturated and undersaturated oil viscosity." },
    { q: "The bubble point pressure of an oil reservoir increases when:", opts: ["Water influx occurs","More solution gas is dissolved in the oil (higher GOR)","Temperature decreases","API gravity decreases"], ans: 1, exp: "Bubble point pressure increases with higher dissolved gas content (GOR). More gas dissolved requires higher pressure to keep it in solution." },
    { q: "What does a GOR of 2000 scf/STB indicate about reservoir fluid type?", opts: ["Black oil","Volatile oil","Gas condensate","Dry gas"], ans: 1, exp: "GOR classification: Black oil <1750 scf/STB, Volatile oil 1750-3300 scf/STB, Gas condensate 3300-100,000 scf/STB, Dry gas >100,000 scf/STB." },
    { q: "The cricondentherm on a phase envelope represents:", opts: ["The maximum pressure at which two phases can coexist","The maximum temperature at which two phases can coexist","The critical point of the mixture","The minimum pressure for single-phase flow"], ans: 1, exp: "Cricondentherm is the maximum temperature at which liquid and vapor can coexist in equilibrium. Above this temperature, only single-phase gas exists regardless of pressure." },
    { q: "Parachor values are used in which fluid property calculation?", opts: ["Viscosity prediction","Interfacial tension (IFT) calculation","Compressibility factor","Heat capacity"], ans: 1, exp: "Parachor values (empirical constants for each component) are used in the MacLeod-Sugden correlation to calculate interfacial tension between oil and gas phases." },
    { q: "A reservoir fluid with a water salinity of 150,000 ppm NaCl equivalent will have a formation water density approximately:", opts: ["1.00 g/cm³","1.10 g/cm³","1.20 g/cm³","0.95 g/cm³"], ans: 1, exp: "Formation water density increases with salinity. At 150,000 ppm (~15% TDS), density ≈ 1.09-1.11 g/cm³. The 1.10 g/cm³ is the most accurate estimate." },
    { q: "In EOS (Equation of State) modeling, the Peng-Robinson EOS is preferred over van der Waals for petroleum fluids because:", opts: ["It requires fewer input parameters","It better predicts liquid density and vapor-liquid equilibria for hydrocarbons","It is computationally faster","It was developed specifically for natural gas systems"], ans: 1, exp: "Peng-Robinson (1976) EOS provides better predictions of liquid densities and VLE for hydrocarbon systems compared to earlier cubic EOS, making it the industry standard for reservoir fluid characterization." },
  ].map((q, i) => ({ moduleId: 10003, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 10004 - Separation Technology
  ...[
    { q: "A three-phase separator operating at 1000 psia and 100°F processes 5000 BOPD with 80% water cut. The required liquid retention time is 3 minutes. What is the minimum liquid volume required?", opts: ["52.5 bbl","87.5 bbl","175 bbl","350 bbl"], ans: 1, exp: "Total liquid = 5000 BOPD / (1-0.8) = 25,000 BLPD. Per minute = 25,000/1440 = 17.36 BPM. Volume = 17.36 × 3 = 52.1 bbl for oil. Total liquid (including water) = 25,000/1440 × 3 = 52.1 bbl oil + water together ≈ 87.5 bbl accounting for both phases." },
    { q: "The Souders-Brown coefficient (K-value) in separator sizing is used to calculate:", opts: ["Liquid retention time","Maximum allowable gas velocity to prevent liquid carryover","Separator wall thickness","Heat duty for gas cooling"], ans: 1, exp: "The Souders-Brown equation: Vmax = K × √((ρL-ρG)/ρG). The K-value (typically 0.12-0.35 ft/s depending on separator type) determines the maximum gas velocity before liquid droplets are entrained." },
    { q: "In a horizontal three-phase separator, the water-oil interface level is controlled by:", opts: ["The gas outlet pressure controller","A level controller on the oil outlet weir","A level controller on the water boot or water outlet","The inlet diverter position"], ans: 2, exp: "In a horizontal 3-phase separator, the water-oil interface is controlled by a level controller (LIC) on the water outlet, while the oil-gas interface is controlled by the oil weir height." },
    { q: "A mist extractor in a separator is designed to remove liquid droplets larger than:", opts: ["1000 microns","100 microns","10 microns","1 micron"], ans: 1, exp: "Wire mesh mist extractors typically remove droplets >100 microns with >99% efficiency. Vane-type extractors handle 10-100 microns. For <10 microns, coalescing filters are needed." },
    { q: "The L/D ratio for a horizontal separator is typically selected in the range of:", opts: ["1:1 to 2:1","3:1 to 5:1","7:1 to 10:1","12:1 to 15:1"], ans: 1, exp: "Horizontal separators typically have L/D ratios of 3:1 to 5:1. This provides sufficient residence time for phase separation while maintaining economical vessel dimensions." },
    { q: "Which separator type is most suitable for handling fluids with high sand/solids content?", opts: ["Vertical separator","Horizontal separator","Spherical separator","Cyclone separator"], ans: 0, exp: "Vertical separators are preferred for high-solids service because solids settle to the bottom cone and can be easily removed via a sand drain, without the risk of plugging the liquid section as in horizontal vessels." },
    { q: "In a gas-liquid separator, increasing operating pressure (at constant temperature) will:", opts: ["Decrease gas density and increase separation efficiency","Increase gas density, reducing the Souders-Brown velocity and potentially improving liquid separation","Have no effect on separation performance","Always decrease liquid carryover"], ans: 1, exp: "Higher pressure increases gas density (ρG), which reduces the density difference (ρL-ρG), lowering the Souders-Brown velocity. However, higher pressure also reduces gas volume, so the net effect depends on the specific conditions." },
    { q: "The primary purpose of a vortex breaker in a separator liquid outlet is to:", opts: ["Increase liquid residence time","Prevent gas entrainment in the liquid outlet by breaking the vortex","Reduce emulsion formation","Improve sand settling"], ans: 1, exp: "A vortex breaker (cross-shaped baffle) prevents a vortex from forming at the liquid outlet nozzle, which would otherwise draw gas down into the liquid line (gas blowby)." },
    { q: "For a gas condensate separator operating near the cricondentherm, the most critical design consideration is:", opts: ["Liquid surge capacity","Prevention of hydrate formation in the gas outlet","Accurate phase equilibrium calculations to determine actual liquid dropout","Sand erosion of internals"], ans: 2, exp: "Near the cricondentherm, small temperature or pressure changes cause significant changes in liquid dropout. Accurate EOS-based phase equilibrium calculations are critical to properly size the liquid section." },
    { q: "A separator test report shows 2% liquid carryover in the gas outlet. The most likely cause is:", opts: ["Insufficient gas retention time","Mist extractor plugging or flooding due to excessive gas velocity","Incorrect weir height","Low operating temperature"], ans: 1, exp: "Liquid carryover in the gas outlet is most commonly caused by: (1) mist extractor flooding due to gas velocity exceeding design limits, (2) mist extractor plugging with paraffin/asphaltene, or (3) foaming." },
  ].map((q, i) => ({ moduleId: 10004, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 10005 - Crude Oil Treatment
  ...[
    { q: "The Reid Vapor Pressure (RVP) specification for crude oil export is typically:", opts: ["<1 psia","<6 psia","<14.7 psia","<20 psia"], ans: 1, exp: "Export crude oil typically requires RVP <6 psia (some specifications allow up to 8 psia) to prevent excessive evaporation during storage and transport and to meet tanker loading safety requirements." },
    { q: "In electrostatic dehydration, the electric field breaks water-in-oil emulsions by:", opts: ["Heating the emulsion to reduce viscosity","Inducing dipole-dipole attraction between water droplets, causing coalescence","Reversing the emulsifier charge","Creating turbulence that breaks the emulsion film"], ans: 1, exp: "AC or DC electric fields polarize water droplets, inducing dipole moments that attract adjacent droplets. This overcomes the stabilizing emulsifier film and promotes coalescence into larger drops that settle by gravity." },
    { q: "BS&W (Basic Sediment and Water) specification for pipeline crude oil is typically:", opts: ["<0.1%","<0.5%","<2%","<5%"], ans: 1, exp: "Pipeline crude oil specifications typically require BS&W <0.5% (some pipelines allow up to 1%). Offshore export crude may have stricter requirements of <0.2-0.3%." },
    { q: "Which chemical demulsifier mechanism is most effective for tight emulsions?", opts: ["Flocculation only","Wettability reversal combined with film thinning and rupture","Simple dilution","pH adjustment"], ans: 1, exp: "Effective demulsifiers work by: (1) adsorbing at the water-oil interface, (2) displacing/weakening the stabilizing emulsifier film, (3) promoting coalescence through wettability reversal and film thinning." },
    { q: "Crude oil stabilization by differential liberation (flash separation) achieves lower RVP compared to single-stage flash because:", opts: ["Higher operating temperature","Multiple equilibrium stages progressively remove lighter components","Higher operating pressure","Longer residence time"], ans: 1, exp: "Multi-stage separation (differential liberation) progressively removes lighter components at each stage. This prevents the lightest components from being 're-dissolved' in the liquid, achieving lower final RVP than single-stage flash." },
    { q: "The salt content specification for crude oil entering a refinery desalter is typically:", opts: ["<10 PTB (pounds per thousand barrels)","<3 PTB","<50 PTB","<100 PTB"], ans: 1, exp: "Refinery desalters typically require crude oil salt content <3 PTB (some specifications allow up to 10 PTB) to prevent corrosion in the crude distillation unit and downstream equipment." },
    { q: "Asphaltene precipitation in crude oil is most likely to occur when:", opts: ["Temperature increases above 80°C","Pressure drops below the bubble point and light ends flash off","Water content increases above 10%","CO2 content decreases"], ans: 1, exp: "Asphaltenes are stabilized in crude oil by resins and light aromatics. When pressure drops below bubble point, light ends flash off, reducing the solvency power of the crude and causing asphaltene precipitation." },
    { q: "In a crude oil heater-treater, the residence time for oil-water separation is typically:", opts: ["30 seconds to 2 minutes","5 to 30 minutes","1 to 4 hours","8 to 24 hours"], ans: 1, exp: "Heater-treaters typically provide 5-30 minutes of liquid residence time. The heat reduces oil viscosity and breaks emulsions, while the residence time allows gravity separation of the coalesced water droplets." },
    { q: "The Stokes' Law settling velocity for water droplets in crude oil is proportional to:", opts: ["Droplet diameter","Square of droplet diameter","Cube of droplet diameter","Square root of droplet diameter"], ans: 1, exp: "Stokes' Law: Vs = (d² × Δρ × g) / (18μ). Settling velocity is proportional to the SQUARE of droplet diameter. Doubling droplet size increases settling velocity by 4×." },
    { q: "Which crude oil treatment problem is indicated by a 'rag layer' at the oil-water interface in a separator?", opts: ["High gas-oil ratio","Stable emulsion stabilized by fine solids (naphthenate soaps, clays, asphaltenes)","High salt content","Low operating temperature"], ans: 1, exp: "A rag layer is a persistent emulsion layer at the oil-water interface, typically stabilized by fine solids (clays, asphaltenes, iron sulfide) and/or naphthenate soaps. It requires specialized treatment chemicals and often mechanical removal." },
  ].map((q, i) => ({ moduleId: 10005, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 10006 - Gas Processing
  ...[
    { q: "In a TEG (Triethylene Glycol) dehydration unit, the lean TEG concentration required to meet a -20°C hydrocarbon dew point specification is approximately:", opts: ["95 wt%","98 wt%","99.5 wt%","99.95 wt%"], ans: 2, exp: "To achieve a -20°C water dew point, lean TEG concentration of approximately 99.0-99.5 wt% is required. For deeper dehydration (-40°C), concentrations of 99.9%+ are needed, often requiring stripping gas." },
    { q: "The Claus process for sulfur recovery from H2S achieves what maximum theoretical sulfur recovery efficiency?", opts: ["85%","95%","99.5%","100%"], ans: 1, exp: "A 3-stage Claus unit achieves approximately 95-97% sulfur recovery. To meet environmental regulations (>99.5%), tail gas treatment units (SCOT, Superclaus) are required." },
    { q: "In amine gas treating, the H2S loading capacity of MDEA (Methyldiethanolamine) compared to DEA is:", opts: ["Lower H2S selectivity but higher CO2 absorption","Higher H2S selectivity with lower CO2 absorption (selective treating)","Equal selectivity for both H2S and CO2","Higher CO2 selectivity only"], ans: 1, exp: "MDEA is a tertiary amine with high selectivity for H2S over CO2. It reacts rapidly with H2S (instantaneous reaction) but slowly with CO2 (requires CO2 hydration step), making it ideal for selective H2S removal." },
    { q: "The hydrocarbon dew point of a gas stream is most accurately determined by:", opts: ["Calculating from gas composition using EOS","Using a chilled mirror dew point analyzer","Using a Joule-Thomson valve test","Calculating from the cricondentherm only"], ans: 0, exp: "Hydrocarbon dew point is most accurately determined by EOS calculation from detailed gas composition (C1-C10+ analysis). Chilled mirror analyzers measure water dew point, not hydrocarbon dew point." },
    { q: "In a gas compression system, the polytropic efficiency of a centrifugal compressor is typically:", opts: ["60-70%","75-85%","88-92%","95-99%"], ans: 1, exp: "Centrifugal compressors typically achieve polytropic efficiencies of 75-85%. Reciprocating compressors achieve higher efficiencies (85-92%) but are limited in flow rate." },
    { q: "Hydrate formation in gas pipelines is prevented by which combination of methods?", opts: ["Heating only","Dehydration, methanol/MEG injection, and/or heating","Pressure reduction only","Increasing gas velocity"], ans: 1, exp: "Hydrate prevention requires keeping conditions outside the hydrate stability zone: (1) dehydration to reduce water content, (2) thermodynamic inhibitors (methanol, MEG) to shift the hydrate curve, (3) heating to maintain temperature above hydrate formation." },
    { q: "The Joule-Thomson coefficient for natural gas at pipeline conditions (high pressure, moderate temperature) is:", opts: ["Negative (gas warms on expansion)","Positive (gas cools on expansion)","Zero (no temperature change)","Variable with no predictable sign"], ans: 1, exp: "Natural gas at pipeline conditions has a positive Joule-Thomson coefficient, meaning it cools when pressure drops through a valve or restriction. This cooling can cause hydrate formation or condensation." },
    { q: "In NGL (Natural Gas Liquids) recovery, the turboexpander process achieves lower temperatures than Joule-Thomson expansion because:", opts: ["It uses external refrigeration","Work is extracted from the gas during expansion, providing additional cooling","It operates at higher pressures","It uses a different gas composition"], ans: 1, exp: "A turboexpander extracts mechanical work from the expanding gas (driving a compressor), providing isentropic cooling rather than isenthalpic cooling (J-T). This achieves 15-25°C lower temperatures for the same pressure drop." },
    { q: "Molecular sieve dehydration is preferred over TEG for which application?", opts: ["High-volume gas dehydration at moderate specifications","Ultra-deep dehydration for LNG feed gas (<1 ppmv water)","Low-pressure gas streams","High CO2 content gas streams"], ans: 1, exp: "Molecular sieves (4A or 3A) can achieve water content <0.1 ppmv, required for LNG liquefaction (to prevent ice formation) and cryogenic NGL recovery. TEG cannot achieve these ultra-low water specifications." },
    { q: "The primary cause of foaming in an amine absorber is:", opts: ["High gas velocity only","Contamination with hydrocarbons, fine solids, or degradation products","High amine concentration","Low operating temperature"], ans: 1, exp: "Amine foaming is caused by: (1) hydrocarbon contamination (liquid carryover from upstream separators), (2) fine solids (iron sulfide, carbon fines), (3) amine degradation products, (4) surfactants. Antifoam injection provides temporary relief." },
  ].map((q, i) => ({ moduleId: 10006, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 10007 - Produced Water Treatment
  ...[
    { q: "The MARPOL 73/78 Annex I regulation limits oil content in overboard discharge to:", opts: ["100 ppm","15 ppm","50 ppm","5 ppm"], ans: 1, exp: "MARPOL Annex I limits oil content in overboard discharge to 15 ppm for vessels in special areas. Some jurisdictions (North Sea, Arctic) have stricter limits of 30 mg/L (30 ppm) for produced water." },
    { q: "In a hydrocyclone for produced water treatment, separation efficiency depends primarily on:", opts: ["Residence time","Centrifugal force generated by inlet velocity and cyclone geometry","Chemical dosing","Operating temperature"], ans: 1, exp: "Hydrocyclone efficiency depends on the centrifugal acceleration (typically 1000-2000g), which is determined by inlet velocity and cyclone geometry (diameter, cone angle). No moving parts - separation is purely by centrifugal force." },
    { q: "The primary mechanism of an induced gas flotation (IGF) unit for produced water treatment is:", opts: ["Gravity settling of oil droplets","Attachment of fine gas bubbles to oil droplets, reducing their effective density for flotation","Chemical oxidation of dissolved organics","Membrane filtration of oil droplets"], ans: 1, exp: "IGF units inject fine gas bubbles (air or gas) that attach to oil droplets, reducing their effective density below water. The oil-bubble agglomerates float to the surface for skimming." },
    { q: "Produced water injection (PWI) for disposal requires the water to meet which critical specification?", opts: ["Low temperature only","Compatibility with formation water and low suspended solids to prevent formation damage","Low salinity","High pH"], ans: 1, exp: "PWI requires: (1) compatibility with formation water to prevent scale/precipitation, (2) low suspended solids (<2-5 ppm) to prevent plugging, (3) low oil content to prevent formation damage. Incompatibility causes irreversible permeability damage." },
    { q: "Scale formation in produced water systems is most commonly caused by:", opts: ["High temperature only","Mixing of incompatible waters (e.g., sulfate-rich seawater with barium-rich formation water)","High flow velocity","Low pH"], ans: 1, exp: "Barium sulfate (BaSO4) scale forms when sulfate-rich injection water mixes with barium-rich formation water. This scale is extremely hard and nearly insoluble, making it very difficult to remove." },
    { q: "The Langelier Saturation Index (LSI) is used to predict:", opts: ["H2S corrosion potential","Calcium carbonate (CaCO3) scaling or corrosion tendency","Bacterial growth rate","Emulsion stability"], ans: 1, exp: "LSI = pH - pHs (saturation pH). LSI > 0: scale-forming tendency; LSI < 0: corrosive tendency; LSI = 0: balanced. Used to predict CaCO3 scaling/corrosion in water systems." },
    { q: "Produced water with high Total Dissolved Solids (TDS >100,000 ppm) is most challenging to treat for reuse because:", opts: ["It is too hot","Conventional membrane processes (RO) cannot handle such high salinity economically","It contains too much oil","It has too low pH"], ans: 1, exp: "Reverse osmosis (RO) membranes have practical TDS limits of ~45,000 ppm. For produced water with TDS >100,000 ppm, only thermal desalination (MVC, MED) or deep well disposal are practical options." },
    { q: "Microbial induced corrosion (MIC) in produced water systems is primarily caused by:", opts: ["Aerobic bacteria only","Sulfate-reducing bacteria (SRB) producing H2S under anaerobic conditions","Acid-producing bacteria only","Fungi"], ans: 1, exp: "SRB (Desulfovibrio, Desulfotomaculum) reduce sulfate to H2S under anaerobic conditions. H2S causes severe corrosion (hydrogen embrittlement, sulfide stress cracking) and can also form iron sulfide scale." },
    { q: "The primary purpose of a skim tank (API separator) in produced water treatment is:", opts: ["Removing dissolved salts","Gravity separation of free oil and settleable solids from water","Chemical oxidation of organics","Biological treatment of dissolved organics"], ans: 1, exp: "API separators use gravity to separate free (non-emulsified) oil droplets >150 microns and settleable solids from water. They are the first stage in produced water treatment, not effective for emulsified oil or dissolved organics." },
    { q: "Produced water reinjection (PWRI) into a water disposal well shows declining injectivity. The most likely cause is:", opts: ["Increasing water temperature","Formation plugging by suspended solids, oil, or bacterial growth","Decreasing reservoir pressure","Increasing water salinity"], ans: 1, exp: "Declining injectivity in PWRI wells is most commonly caused by: (1) suspended solids plugging near-wellbore pores, (2) oil droplets coating pore throats, (3) bacterial growth forming biofilms, (4) scale precipitation. Regular backflushing or acid stimulation may be required." },
  ].map((q, i) => ({ moduleId: 10007, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 10008 - Utility Systems
  ...[
    { q: "Instrument air quality requirements per ISA-7.0.01 specify a dew point of:", opts: ["0°C at line pressure","At least 10°C below minimum ambient temperature at line pressure","-40°C at atmospheric pressure","<1% relative humidity at operating temperature"], ans: 1, exp: "ISA-7.0.01 requires instrument air dew point to be at least 10°C (18°F) below the minimum ambient temperature at line pressure to prevent condensation in instrument tubing and pneumatic devices." },
    { q: "The primary purpose of a flare knockout drum (KOD) is:", opts: ["To ignite the flare gas","To remove liquid droplets from the gas stream before the flare tip to prevent liquid rain","To measure flare gas flow rate","To reduce flare gas pressure"], ans: 1, exp: "The KOD (also called flare liquid knockout drum) removes entrained liquid droplets from the flare header. Liquid reaching the flare tip causes 'liquid rain' (burning liquid droplets falling to grade), a serious safety hazard." },
    { q: "In a fuel gas system, the minimum heating value required for stable combustion in gas turbines is typically:", opts: ["200 BTU/scf","500 BTU/scf","900 BTU/scf","1500 BTU/scf"], ans: 2, exp: "Gas turbines typically require fuel gas with LHV >900 BTU/scf (>33.5 MJ/Nm³) for stable combustion. Lean gas (high N2 or CO2 content) may require supplemental fuel or modified combustors." },
    { q: "The Wobbe Index is used to characterize fuel gas interchangeability because it accounts for:", opts: ["Gas density only","Both heating value and specific gravity, predicting thermal input at constant pressure drop","Gas viscosity and flow rate","Combustion temperature only"], ans: 1, exp: "Wobbe Index = HHV / √(SG). It predicts the thermal input to a burner at constant pressure drop, allowing comparison of different gas compositions. Gases with similar Wobbe Index are interchangeable without burner adjustment." },
    { q: "Nitrogen blanketing of crude oil storage tanks serves what primary purpose?", opts: ["Cooling the crude oil","Preventing explosive hydrocarbon-air mixtures in the vapor space","Increasing crude oil API gravity","Reducing crude oil viscosity"], ans: 1, exp: "Nitrogen blanketing maintains an inert atmosphere in the tank vapor space, preventing the formation of explosive hydrocarbon-air mixtures. It also reduces evaporation losses and prevents oxygen-induced corrosion." },
    { q: "A chemical injection pump for scale inhibitor dosing is sized based on:", opts: ["Maximum flow rate only","Injection rate (ppm × water production rate) and back-pressure at injection point","Minimum flow rate only","Chemical viscosity only"], ans: 1, exp: "Chemical injection pump sizing: (1) Flow rate = dosage (ppm) × water rate (BPD) × conversion factor, (2) Discharge pressure must exceed maximum system pressure at injection point + 10-20% margin." },
    { q: "The purpose of a pressure safety valve (PSV) test in utility systems is to verify:", opts: ["That the valve opens at exactly set pressure","That the valve opens at or below set pressure and reseats properly","That the valve never opens","That the valve flow capacity exceeds design"], ans: 1, exp: "PSV testing verifies: (1) opening pressure ≤ set pressure (within ±3% per API 527), (2) full lift at 10% overpressure, (3) proper reseating (blowdown) after relieving. Valves that open above set pressure are unsafe." },
    { q: "In a cooling water system, the Langelier Saturation Index (LSI) is maintained slightly positive (+0.2 to +0.5) to:", opts: ["Maximize biocide effectiveness","Form a thin protective CaCO3 film on pipe surfaces to reduce corrosion","Prevent microbiological growth","Increase heat transfer efficiency"], ans: 1, exp: "A slightly positive LSI (+0.2 to +0.5) promotes formation of a thin protective CaCO3 film on metal surfaces, reducing corrosion. LSI too negative = corrosive; LSI too positive = heavy scaling and fouling." },
    { q: "The minimum safe distance for a flare stack from process equipment per API 521 is determined by:", opts: ["A fixed distance of 100 meters","Thermal radiation calculations limiting heat flux to 1500 BTU/hr·ft² at grade","Stack height only","Wind direction only"], ans: 1, exp: "API 521 specifies maximum allowable thermal radiation levels: 1500 BTU/hr·ft² (4.73 kW/m²) for personnel with limited exposure, 500 BTU/hr·ft² for areas with continuous personnel presence. Flare location is determined by radiation calculations." },
    { q: "A diesel generator set for emergency power in an oil facility must be capable of reaching full load within:", opts: ["30 seconds","10 seconds","5 minutes","1 minute"], ans: 1, exp: "Emergency diesel generators (EDG) per IEC 60034 and facility standards must reach full load within 10 seconds of loss of normal power to ensure continuity of safety-critical systems (ESD, fire & gas, emergency lighting)." },
  ].map((q, i) => ({ moduleId: 10008, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 10009 - Safety, Metering and Process Design
  ...[
    { q: "In a HAZOP study, the guideword 'REVERSE' applied to the parameter 'FLOW' identifies:", opts: ["Zero flow condition","Backflow or reverse flow scenario","Excess flow","Incorrect direction of flow in a different line"], ans: 1, exp: "HAZOP guideword REVERSE + FLOW = reverse/backflow scenario. This identifies risks such as backflow through a pump, reverse flow through a check valve failure, or siphoning." },
    { q: "A Safety Integrity Level (SIL) 2 safety function requires a Probability of Failure on Demand (PFD) in the range:", opts: ["10⁻¹ to 10⁻²","10⁻² to 10⁻³","10⁻³ to 10⁻⁴","10⁻⁴ to 10⁻⁵"], ans: 1, exp: "Per IEC 61511: SIL 1: PFD 10⁻¹ to 10⁻², SIL 2: PFD 10⁻² to 10⁻³, SIL 3: PFD 10⁻³ to 10⁻⁴, SIL 4: PFD 10⁻⁴ to 10⁻⁵." },
    { q: "The primary standard for fiscal metering of crude oil is:", opts: ["API MPMS Chapter 5","ISO 5167","AGA Report No. 3","OIML R117"], ans: 0, exp: "API Manual of Petroleum Measurement Standards (MPMS) Chapter 5 covers displacement meters for liquid hydrocarbons. Chapter 4 covers proving, Chapter 12 covers calculation. API MPMS is the primary standard for fiscal crude metering." },
    { q: "In process design, the design pressure of a pressure vessel is typically set at:", opts: ["Operating pressure","Operating pressure + 10% or + 25 psi (whichever is greater)","Maximum allowable working pressure (MAWP)","Hydrostatic test pressure"], ans: 1, exp: "Design pressure = Operating pressure + 10% (or +25 psi, whichever is greater) per ASME VIII. This provides margin for pressure surges and control upsets. MAWP is calculated from design pressure and actual construction." },
    { q: "A fire & gas detection system classified as 'voting logic 2oo3' means:", opts: ["Two detectors must fail before alarm","Two out of three detectors must activate to initiate a response","Three detectors must all activate simultaneously","One detector activates alarm, two activate shutdown"], ans: 1, exp: "2oo3 (two-out-of-three) voting logic requires at least 2 of 3 detectors to activate before initiating a response. This reduces false trips (vs 1oo3) while maintaining safety (vs 3oo3)." },
    { q: "The ALARP principle in risk management means:", opts: ["All risks must be eliminated","Risks must be reduced As Low As Reasonably Practicable, balancing risk reduction against cost and effort","Risks are acceptable if below a fixed threshold","All risks require engineering controls"], ans: 1, exp: "ALARP (As Low As Reasonably Practicable) requires risk reduction until further reduction is grossly disproportionate to the benefit gained. It balances safety improvement against cost, time, and effort." },
    { q: "In a coriolis flow meter for crude oil fiscal metering, the measurement principle is based on:", opts: ["Differential pressure across an orifice","Inertial forces on the fluid causing tube vibration phase shift proportional to mass flow","Ultrasonic transit time difference","Magnetic induction in conductive fluids"], ans: 1, exp: "Coriolis meters measure the phase shift (time difference) in vibration between inlet and outlet sections of a vibrating tube caused by the Coriolis effect. This phase shift is directly proportional to mass flow rate, independent of fluid properties." },
    { q: "The minimum required thickness for a process vessel shell per ASME Section VIII Div. 1 is calculated using:", opts: ["Hoop stress formula only","The greater of hoop stress (circumferential) or longitudinal stress calculations","Longitudinal stress formula only","Buckling analysis only"], ans: 1, exp: "ASME VIII Div. 1 requires calculating thickness for both hoop stress (t = PR/SE-0.6P) and longitudinal stress (t = PR/2SE+0.4P), then using the greater value. Hoop stress typically governs for cylindrical shells." },
    { q: "In a Process Flow Diagram (PFD), which information is NOT typically shown?", opts: ["Major equipment items and their design conditions","Instrument tag numbers and control loop details","Mass/energy balance data","Major process streams and their compositions"], ans: 1, exp: "PFDs show major equipment, process streams, operating conditions, and mass/energy balances. Instrument tag numbers, control loops, and detailed piping information are shown on P&IDs (Piping and Instrumentation Diagrams)." },
    { q: "The purpose of a pressure relief valve (PRV) 'accumulation' allowance in ASME code is:", opts: ["Extra pressure for pump operation","The maximum allowable pressure above MAWP during a relief event (typically 10% for single PRV)","Pressure drop across the PRV","Backpressure from the flare system"], ans: 1, exp: "Accumulation = maximum pressure above MAWP during relief. ASME allows 10% accumulation for single PRV, 16% for fire case, 21% for multiple PRVs. The PRV must be fully open at 10% overpressure (accumulation)." },
  ].map((q, i) => ({ moduleId: 10009, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // ─── Wellhead Course ──────────────────────────────────────
  // Module 30001 - Wellhead Introduction
  ...[
    { q: "According to API 6A, the maximum allowable working pressure (MAWP) for a 20K wellhead system is:", opts: ["15,000 psi","20,000 psi","25,000 psi","30,000 psi"], ans: 1, exp: "API 6A defines pressure ratings: 2K, 3K, 5K, 10K, 15K, and 20K (20,000 psi). The 20K rating is the highest standard pressure class for wellhead equipment." },
    { q: "The primary function of the tubing hanger in a wellhead assembly is to:", opts: ["Support the weight of the casing string","Suspend the production tubing string and provide a seal between tubing and casing annulus","Provide the primary well barrier","Connect the Christmas tree to the casing head"], ans: 1, exp: "The tubing hanger suspends the production tubing string and provides a metal-to-metal or elastomeric seal between the tubing and casing annulus, preventing annular flow to surface." },
    { q: "Which API 6A material class is required for sour service (H2S) wells?", opts: ["Material Class AA (general service)","Material Class DD, EE, FF, or HH (sour service)","Material Class BB (moderate service)","Material Class CC (high temperature)"], ans: 1, exp: "API 6A Material Classes DD, EE, FF, and HH are designated for sour service per NACE MR0175/ISO 15156. These classes specify hardness limits and material requirements to prevent sulfide stress cracking (SSC)." },
    { q: "The annular pressure buildup (APB) in a sealed casing annulus is primarily caused by:", opts: ["Gas migration from the reservoir","Thermal expansion of trapped fluid during production heating","Cement failure","Casing corrosion"], ans: 1, exp: "APB occurs when production heats the wellbore, causing thermal expansion of fluid trapped in sealed annuli. This can generate pressures exceeding casing burst ratings if not managed through pressure relief or annulus monitoring." },
    { q: "A wellhead rated at 10K-T-U-DD per API 6A indicates:", opts: ["10,000 psi working pressure, Temperature class T, Material class DD","10,000 psi test pressure, Temperature class U, Material class D","10,000 psi working pressure, Temperature class U, Material class DD","10K flow rate, Temperature T, Ductile material DD"], ans: 2, exp: "API 6A designation: 10K = 10,000 psi working pressure, T = Temperature class (-60°F to 250°F), U = Temperature class (-60°F to 350°F), DD = Material class for sour service. So 10K-T-U-DD = 10,000 psi, temp class U, sour service material." },
    { q: "The 'lockdown' mechanism in a tubing hanger is designed to:", opts: ["Prevent rotation of the hanger","Resist upward movement of the tubing string due to pressure and thermal loads","Lock the Christmas tree in place","Prevent the hanger from being retrieved"], ans: 1, exp: "Tubing hanger lockdown prevents upward movement (lifting) of the tubing string caused by: (1) wellbore pressure acting on the tubing cross-sectional area, (2) thermal expansion during production, (3) fluid hammer effects." },
    { q: "In a dual completion wellhead, the primary advantage over a single completion is:", opts: ["Lower cost","Ability to produce from two separate reservoir zones simultaneously without commingling","Higher pressure rating","Simpler maintenance"], ans: 1, exp: "Dual completions allow simultaneous production from two separate reservoir zones through independent tubing strings, maintaining zone isolation for reservoir management, production allocation, and individual zone treatment." },
    { q: "The API 6A hydrostatic body test pressure for a 5000 psi rated wellhead is:", opts: ["5,000 psi","7,500 psi","10,000 psi","15,000 psi"], ans: 1, exp: "API 6A requires hydrostatic body test pressure = 1.5 × working pressure. For 5,000 psi WP: test pressure = 7,500 psi. This verifies structural integrity of the pressure-containing envelope." },
    { q: "Casing head housing (CHH) is distinguished from a casing spool by:", opts: ["CHH is used offshore only","CHH is the first component welded to the surface casing with a bottom flange, while spools have both top and bottom flanges","CHH has higher pressure rating","CHH is made of stainless steel"], ans: 1, exp: "The Casing Head Housing (CHH) is the first wellhead component, welded or threaded to the surface casing. It has a bottom connection to the casing and a top flange. Casing spools have both top and bottom flanges for stacking." },
    { q: "The purpose of a 'tree cap' on a Christmas tree is:", opts: ["To protect the tree from weather","To provide a secondary barrier above the master valve when the well is shut in","To connect the flowline","To house the choke valve"], ans: 1, exp: "The tree cap provides a secondary pressure barrier above the upper master valve (UMV) when the well is shut in. It also protects the tree bore from contamination and provides a test port for barrier verification." },
  ].map((q, i) => ({ moduleId: 30001, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30002 - Onshore vs Offshore Wellhead Types
  ...[
    { q: "A subsea wellhead system rated to 10,000 ft water depth must comply with which API standard?", opts: ["API 6A","API 17D","API 16A","API 6D"], ans: 1, exp: "API 17D covers subsea wellhead and Christmas tree equipment. API 6A covers surface wellhead equipment. Subsea systems have additional requirements for ROV operability, corrosion protection, and hydrostatic pressure." },
    { q: "The primary difference between a 'dry tree' and 'wet tree' completion in offshore wells is:", opts: ["Dry trees are onshore; wet trees are offshore","Dry trees have the Christmas tree on the platform/vessel at surface; wet trees have it on the seabed","Dry trees handle oil only; wet trees handle gas","Dry trees are permanent; wet trees are temporary"], ans: 1, exp: "Dry tree: Christmas tree at surface (on platform or TLP), requires a riser from seabed to surface. Wet tree: Christmas tree on seabed, requires subsea control systems and flowlines. Wet trees are more common for deepwater." },
    { q: "In a mudline suspension (MLS) system, the primary advantage is:", opts: ["Higher pressure rating","Ability to retrieve the wellhead equipment without pulling the casing strings","Lower cost","Simpler installation"], ans: 1, exp: "MLS allows retrieval of wellhead equipment (hangers, seals) from the mudline without pulling the casing strings. This is critical for jack-up drilling where the wellhead must be temporarily abandoned between drilling and completion phases." },
    { q: "The 'conductor tensioner' system on a floating drilling vessel is required to:", opts: ["Provide structural support for the BOP stack","Compensate for vessel heave while maintaining constant tension on the marine riser","Control the direction of the conductor casing","Provide emergency disconnect capability"], ans: 1, exp: "Riser tensioners maintain constant tension on the marine riser despite vessel heave (up/down motion). Without tensioners, vessel heave would alternately compress and tension the riser, causing fatigue damage and potential collapse." },
    { q: "A subsea wellhead with a 'high-pressure housing' (HPH) is designed for:", opts: ["Shallow water only","High-pressure, high-temperature (HPHT) wells requiring 15K or 20K pressure ratings","Standard pressure wells only","Gas wells only"], ans: 1, exp: "High-pressure housings (HPH) are used for HPHT wells requiring 15K or 20K pressure ratings. They have larger bore sizes and heavier construction than standard housings to handle extreme pressures and temperatures." },
    { q: "The 'emergency disconnect package' (EDP) on a subsea BOP stack is activated when:", opts: ["Routine maintenance is required","The drilling vessel must move off location quickly due to weather or emergency","Casing is being run","Cement is being pumped"], ans: 1, exp: "The EDP provides rapid disconnection of the lower marine riser package (LMRP) from the BOP stack in emergencies (severe weather, drive-off, loss of dynamic positioning). It seals the well before disconnection." },
    { q: "Cathodic protection for subsea wellhead equipment is typically provided by:", opts: ["Impressed current only","Sacrificial anodes (zinc or aluminum alloy) attached to the structure","Protective coatings only","Stainless steel construction"], ans: 1, exp: "Subsea wellheads use sacrificial anodes (zinc or aluminum alloys) for cathodic protection. Impressed current systems are used for larger structures (pipelines, platforms). Anodes must be sized for the design life (typically 20-25 years)." },
    { q: "The 'wellhead connector' on a subsea Christmas tree must be capable of:", opts: ["Supporting the weight of the tree only","Providing a pressure-tight connection and resisting all loads (weight, bending, tension) during installation and operation","Connecting to the flowline only","Providing electrical connections only"], ans: 1, exp: "Subsea wellhead connectors must: (1) provide a metal-to-metal pressure seal rated to full wellhead WP, (2) resist structural loads (bending moments from riser, weight of tree), (3) allow ROV-operated connection/disconnection." },
    { q: "In an FPSO (Floating Production Storage and Offloading) development, the wellhead equipment is typically:", opts: ["Mounted on the FPSO hull","Subsea wet trees connected to the FPSO via flexible risers and umbilicals","Dry trees on a separate fixed platform","Mounted on a TLP (Tension Leg Platform)"], ans: 1, exp: "FPSOs typically use subsea wet trees connected via flexible risers (for production) and umbilicals (for control, chemicals, hydraulics). The FPSO's mooring system accommodates weathervaning, making subsea trees the practical choice." },
    { q: "The 'acoustic positioning' system used during subsea wellhead installation provides:", opts: ["Communication with the drilling vessel","Real-time position data of the running tool relative to the wellhead for precise landing","Depth measurement only","Leak detection capability"], ans: 1, exp: "Acoustic positioning (USBL or LBL) provides real-time 3D position data of subsea equipment during installation. This is critical for precise alignment of trees, manifolds, and connectors on the seabed." },
  ].map((q, i) => ({ moduleId: 30002, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30003 - Wellhead Valves
  ...[
    { q: "A gate valve in a wellhead Christmas tree is classified as a 'through-conduit' design. This means:", opts: ["The valve has a full-bore opening equal to the pipe bore","The gate slides through a conduit to open/close","The valve can be used for throttling","The valve has a reduced bore for flow control"], ans: 0, exp: "Through-conduit gate valves have a gate with a hole that aligns with the pipe bore when open, providing a full-bore, unrestricted flow path. This minimizes pressure drop and allows pigging/wireline operations." },
    { q: "The Cv (flow coefficient) of a valve is defined as:", opts: ["The pressure drop across the valve at full open","The flow rate in GPM of water that produces a 1 psi pressure drop at full open","The valve's resistance to flow","The ratio of valve opening to maximum opening"], ans: 1, exp: "Cv = Q × √(SG/ΔP) where Q is flow in GPM and ΔP is pressure drop in psi for water (SG=1). Cv represents the flow capacity of the valve at full open with 1 psi differential pressure." },
    { q: "A surface-controlled subsurface safety valve (SCSSV) is required to fail to which position on loss of control pressure?", opts: ["Fail open","Fail closed (fail-safe closed)","Fail in last position","Fail to 50% open"], ans: 1, exp: "SCSSVs are fail-safe closed: they require hydraulic pressure to remain open. Loss of control pressure (line failure, emergency) causes the spring to close the valve, providing a downhole barrier against uncontrolled flow." },
    { q: "The choke valve in a wellhead Christmas tree is designed for:", opts: ["Emergency isolation only","Controlling production flow rate and wellhead pressure by creating a pressure drop","Full-bore isolation","Gas lift injection control only"], ans: 1, exp: "The choke valve controls production rate by creating a controlled pressure drop. Adjustable chokes allow variable flow control; fixed chokes provide constant restriction. Critical flow (sonic flow) through the choke makes flow rate independent of downstream pressure." },
    { q: "In a wellhead ball valve, the 'trunnion-mounted' design is preferred over 'floating ball' for large bore, high-pressure applications because:", opts: ["Lower cost","The trunnion supports the ball, reducing seat load and operating torque at high pressure","Higher flow coefficient","Simpler maintenance"], ans: 1, exp: "In trunnion-mounted ball valves, the ball is supported by trunnions (shafts), so line pressure does not load the seats. This dramatically reduces operating torque at high pressures, making large-bore, high-pressure valves operable with reasonable actuator forces." },
    { q: "The 'double block and bleed' (DBB) configuration in wellhead valve isolation requires:", opts: ["One valve and one check valve","Two independent isolation valves with a bleed valve between them to verify isolation and drain the cavity","Two valves in series without a bleed","One valve with dual seats"], ans: 1, exp: "DBB = two independent isolation valves (block valves) with a bleed valve between them. After closing both block valves, the bleed is opened to: (1) verify both valves are holding (no pressure buildup), (2) drain/depressurize the cavity for safe maintenance." },
    { q: "A wellhead gate valve showing 'back-seat' leakage indicates:", opts: ["Seat damage causing through-leakage","Stem packing failure allowing leakage past the back-seat when the valve is fully open","Gate damage","Bonnet bolt failure"], ans: 1, exp: "The back-seat is a secondary seal between the gate/stem and bonnet that engages when the valve is fully open. Back-seat leakage indicates packing failure; the back-seat allows packing replacement under pressure when the valve is fully open." },
    { q: "The 'trim' of a wellhead choke valve refers to:", opts: ["The external finish of the valve body","The internal components (cage, plug, seat) that control flow and determine the Cv characteristic","The valve's pressure rating","The actuator type"], ans: 1, exp: "Valve trim = internal flow control components: cage (with flow holes), plug, and seat. Trim determines: (1) flow characteristic (linear, equal percentage), (2) Cv at each position, (3) material selection for erosion/corrosion resistance." },
    { q: "In a wellhead check valve, the 'cracking pressure' is defined as:", opts: ["The pressure at which the valve fully opens","The minimum differential pressure required to open the valve from its closed position","The maximum allowable pressure","The pressure at which the valve fails"], ans: 1, exp: "Cracking pressure is the minimum upstream pressure required to overcome the spring force and open the check valve. It is typically 1-5 psi for swing check valves and higher for spring-loaded designs." },
    { q: "Wellhead valve actuators are classified as 'fail-safe' based on their action on loss of power/signal. A 'fail-close' actuator on a production master valve is used because:", opts: ["It is cheaper","Loss of power should close the well to prevent uncontrolled flow (safety-critical application)","It requires less maintenance","It is faster to operate"], ans: 1, exp: "Production master valves use fail-close actuators because the safe state on loss of power/signal is well closure. This prevents uncontrolled flow in emergencies (fire, ESD activation, power failure), implementing the safety function." },
  ].map((q, i) => ({ moduleId: 30003, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30004 - Wellhead Sealing Systems
  ...[
    { q: "A BX ring joint gasket is used in wellhead flanges instead of RX because:", opts: ["BX is cheaper","BX provides a self-energizing seal that becomes tighter with increasing pressure, suitable for HPHT applications","BX has lower contact stress","BX is easier to install"], ans: 1, exp: "BX ring joints are self-energizing: increasing pressure forces the ring harder against the grooves, improving the seal. They are used for 5K+ pressure ratings. RX rings are also self-energizing but BX provides better performance at extreme pressures." },
    { q: "The API 6A leak test for a wellhead body seal requires:", opts: ["Testing at 1.5× working pressure for 15 minutes","Testing at working pressure for a minimum period with zero pressure drop","Testing at 0.5× working pressure","Visual inspection only"], ans: 1, exp: "API 6A PR2 qualification requires body pressure tests at rated working pressure with zero allowable pressure drop over the test period. The test duration varies by pressure rating (typically 15-30 minutes)." },
    { q: "Metal-to-metal seals in wellhead equipment are preferred over elastomeric seals for HPHT applications because:", opts: ["Lower cost","Reliability at high temperature (>150°C) where elastomers degrade, and resistance to H2S/CO2 chemical attack","Easier installation","Lower contact stress requirements"], ans: 1, exp: "Elastomers degrade above 150-175°C and are attacked by H2S, CO2, and aromatic solvents. Metal-to-metal seals maintain integrity at temperatures >300°C and are chemically inert, making them essential for HPHT and sour service." },
    { q: "The 'seal assembly' in a casing hanger provides which type of isolation?", opts: ["Only annular isolation","Both annular isolation (between casing strings) and load transfer from hanger to wellhead housing","Only structural support","Only corrosion protection"], ans: 1, exp: "The casing hanger seal assembly: (1) provides annular isolation between adjacent casing strings (primary well barrier), (2) transfers the weight of the casing string to the wellhead housing, (3) may include a lockdown mechanism." },
    { q: "In API 6A, the 'PR1' and 'PR2' qualification levels differ in that:", opts: ["PR1 is for higher pressure ratings","PR2 requires more extensive qualification testing including cyclic pressure, temperature, and bending load tests","PR1 requires more tests","PR2 is for subsea equipment only"], ans: 1, exp: "PR1 = basic qualification (hydrostatic body test, seat test). PR2 = full qualification including: cyclic pressure tests, temperature cycling, bending load tests, and gas tests. PR2 is required for critical applications and HPHT service." },
    { q: "A wellhead flange connection showing 'weeping' at the ring groove indicates:", opts: ["Normal behavior","Seal failure due to insufficient bolt load, ring damage, or groove damage","Excessive bolt load","Thermal expansion"], ans: 1, exp: "Weeping at ring grooves indicates seal failure. Causes: (1) insufficient bolt preload (under-torqued bolts), (2) ring gasket damage (scratches, corrosion), (3) groove damage (scoring, corrosion), (4) thermal cycling causing bolt relaxation." },
    { q: "The purpose of 'lock screws' in a casing hanger is to:", opts: ["Prevent rotation during installation","Provide secondary lockdown against upward movement after the primary lockdown is set","Connect the hanger to the wellhead","Provide a test port"], ans: 1, exp: "Lock screws (or lock ring) provide a secondary mechanical lockdown of the casing hanger in the wellhead housing, preventing upward movement due to annular pressure or thermal loads. They supplement the primary lockdown mechanism." },
    { q: "The 'energization' of a metal seal in a wellhead requires:", opts: ["High temperature only","Controlled application of load (typically by running tool hydraulics or bolting) to plastically deform the seal and create intimate metal contact","Chemical treatment","Pressure testing only"], ans: 1, exp: "Metal seals require energization: controlled plastic deformation of the seal material to create intimate contact with the mating surfaces. This is achieved by applying a specific load (torque or hydraulic force) during installation." },
    { q: "API 6A specifies the maximum allowable leakage rate for a wellhead seat test as:", opts: ["Zero leakage for all tests","Zero leakage for gas test; limited leakage for liquid test","5 cc/min for all tests","10 cc/min for gas, zero for liquid"], ans: 0, exp: "API 6A requires ZERO leakage for both gas and liquid seat tests. Any measurable leakage constitutes a test failure. This is critical for well barrier integrity." },
    { q: "The 'test port' between the two seals in a dual-seal wellhead configuration is used to:", opts: ["Measure flow rate","Verify the integrity of both seals independently by pressure testing the annular space between them","Inject chemicals","Monitor temperature"], ans: 1, exp: "The test port between dual seals allows: (1) pressure testing of the inner seal from outside, (2) pressure testing of the outer seal from inside, (3) monitoring for leakage past the inner seal during operation, (4) venting trapped pressure." },
  ].map((q, i) => ({ moduleId: 30004, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30005 - Pressure and Temperature Ratings
  ...[
    { q: "API 6A Temperature Class 'U' covers the range:", opts: ["-20°F to 250°F","-60°F to 350°F","-75°F to 400°F","0°F to 250°F"], ans: 1, exp: "API 6A Temperature Classes: K (-75°F to 180°F), L (-50°F to 180°F), P (-20°F to 180°F), R (ambient to 180°F), S (-20°F to 250°F), T (-20°F to 350°F), U (-60°F to 350°F), V (-20°F to 350°F)." },
    { q: "The design temperature for a wellhead system in a geothermal well reaching 300°C requires which API 6A temperature class?", opts: ["Class T","Class U","Class V","None of the standard classes - special design required"], ans: 3, exp: "API 6A standard temperature classes only go up to 350°F (177°C) for Class U/V. A 300°C (572°F) geothermal well exceeds all standard API 6A temperature classes, requiring special design and qualification testing." },
    { q: "The 'working pressure' of a wellhead component per API 6A is defined as:", opts: ["The maximum pressure during a pressure test","The maximum pressure the component can sustain in continuous service at rated temperature","The design pressure used for wall thickness calculations","The burst pressure divided by a safety factor"], ans: 1, exp: "Working pressure (WP) = maximum pressure the component can sustain in continuous service at the rated temperature. It is the basis for all API 6A pressure ratings (2K, 3K, 5K, 10K, 15K, 20K)." },
    { q: "A wellhead rated at 10,000 psi WP is to be used at 350°F. Per API 6A, the derated working pressure at this temperature is:", opts: ["10,000 psi (no derating)","Approximately 9,000 psi","Approximately 7,500 psi","Approximately 5,000 psi"], ans: 0, exp: "API 6A working pressure ratings are valid up to the maximum rated temperature for that class. For Class U (-60°F to 350°F), the 10K rating applies at all temperatures within the class range including 350°F - no derating is required within the rated temperature range." },
    { q: "The 'pressure-temperature rating' curve for a flanged connection shows that as temperature increases:", opts: ["Allowable pressure increases","Allowable pressure decreases due to reduction in material yield strength","Allowable pressure remains constant","Allowable pressure increases then decreases"], ans: 1, exp: "As temperature increases, material yield strength decreases, reducing the allowable pressure. P-T rating curves (per ASME B16.5 for flanges) show the maximum allowable pressure at each temperature for each material class." },
    { q: "For a wellhead system with a maximum anticipated shut-in tubing pressure (SITP) of 8,500 psi, the minimum required API 6A pressure class is:", opts: ["5K (5,000 psi)","10K (10,000 psi)","15K (15,000 psi)","20K (20,000 psi)"], ans: 1, exp: "The wellhead pressure class must exceed the maximum anticipated pressure. With SITP of 8,500 psi, the 5K class (5,000 psi) is insufficient. The 10K class (10,000 psi) is the minimum required, providing adequate margin above 8,500 psi." },
    { q: "The 'collapse pressure' of a wellhead component is relevant when:", opts: ["Internal pressure exceeds external pressure","External pressure exceeds internal pressure (e.g., subsea wellheads during installation, or vacuum conditions)","Temperature exceeds rated temperature","Flow velocity exceeds design limits"], ans: 1, exp: "Collapse occurs when external pressure exceeds internal pressure. Relevant for: (1) subsea wellheads during lowering (hydrostatic pressure before well is open), (2) vacuum conditions in process equipment, (3) wellhead components during well kill operations." },
    { q: "API 6A specifies that the hydrostatic shell test pressure for a 15K rated component is:", opts: ["15,000 psi","22,500 psi","30,000 psi","45,000 psi"], ans: 1, exp: "API 6A hydrostatic shell test = 1.5 × working pressure. For 15K: 1.5 × 15,000 = 22,500 psi. This test verifies the structural integrity of the pressure-containing envelope." },
    { q: "The 'temperature class' of a wellhead component must be selected based on:", opts: ["Maximum operating temperature only","Both minimum and maximum temperature extremes (e.g., cold climate startup and maximum production temperature)","Average operating temperature","Ambient temperature only"], ans: 1, exp: "Temperature class selection must consider both extremes: (1) minimum temperature (cold climate, cold startup, hydrate inhibitor injection) to avoid brittle fracture, (2) maximum temperature (reservoir temperature, steam injection, geothermal) to maintain material strength." },
    { q: "In HPHT (High Pressure High Temperature) wellhead design, the primary additional challenge compared to standard wells is:", opts: ["Higher cost only","Combined effects of high pressure and high temperature on seal integrity, material properties, and thermal stress","Greater depth only","Higher flow rates"], ans: 1, exp: "HPHT wells (typically >10,000 psi and >150°C) present combined challenges: (1) thermal degradation of elastomers, (2) thermal stress from temperature differentials, (3) creep of metal seals, (4) reduced material strength at high temperature, (5) complex phase behavior." },
  ].map((q, i) => ({ moduleId: 30005, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30006 - Installation Procedures
  ...[
    { q: "The correct sequence for installing a wellhead casing head on a new well is:", opts: ["Install Christmas tree first, then casing head","Weld/thread casing head to conductor casing before drilling out, then install subsequent components as each casing string is run","Install all components simultaneously","Install tubing hanger first, then casing head"], ans: 1, exp: "Wellhead installation sequence: (1) Install casing head housing (CHH) on conductor casing, (2) drill out and run surface casing, (3) install casing spool on surface casing, (4) drill and run intermediate/production casing, (5) install tubing head, (6) run tubing, (7) install Christmas tree." },
    { q: "The torque specification for wellhead flange bolts is critical because:", opts: ["Higher torque is always better","Insufficient torque causes seal leakage; excessive torque causes bolt yielding and potential seal extrusion","Torque has no effect on seal performance","Only hand-tight torque is required"], ans: 1, exp: "Correct bolt torque is critical: (1) insufficient torque = inadequate gasket seating stress = leakage, (2) excessive torque = bolt yielding, gasket extrusion, flange rotation = leakage or structural failure. API 6A specifies torque values for each flange size and bolt grade." },
    { q: "Before installing a wellhead component, the ring groove must be inspected for:", opts: ["Color only","Scratches, corrosion pitting, out-of-roundness, and dimensional compliance with API 6A tolerances","Weight only","Manufacturer's label"], ans: 1, exp: "Ring groove inspection: (1) surface finish (scratches >0.25mm depth are rejectable), (2) corrosion pitting, (3) dimensional check (groove width, depth, angle per API 6A), (4) out-of-roundness. Any defect can compromise seal integrity." },
    { q: "The 'running tool' for a subsea wellhead is designed to:", opts: ["Drill the wellbore","Install and retrieve wellhead components (hangers, seals) from the surface via the drill string or wireline","Measure wellbore pressure","Cement the casing"], ans: 1, exp: "Running tools are specialized tools that: (1) latch onto wellhead components, (2) lower them to the correct position, (3) apply the required installation load (torque, set-down weight, hydraulic force), (4) verify proper installation, (5) release and retrieve to surface." },
    { q: "After installing a new wellhead, the first pressure test should be:", opts: ["At maximum wellhead working pressure","A low-pressure test (typically 300-500 psi) to verify seal assembly before high-pressure testing","At 1.5× working pressure immediately","At operating pressure only"], ans: 1, exp: "Testing sequence: (1) low-pressure test (300-500 psi gas or water) to verify basic seal integrity and identify gross leaks, (2) high-pressure test at rated working pressure, (3) final verification. Starting with low pressure prevents damage from sudden high-pressure failures." },
    { q: "The 'stump test' of a Christmas tree before installation verifies:", opts: ["The tree's weight","All valve functions, seal integrity, and control system operation in a controlled surface environment before offshore installation","The tree's dimensions","The tree's material certification"], ans: 1, exp: "Stump testing (factory acceptance test): (1) pressure tests all seals and valve seats, (2) function tests all valves and actuators, (3) tests control system (hydraulic, electrical), (4) verifies dimensional compatibility with wellhead. Identifies problems before costly offshore installation." },
    { q: "When making up a ring joint flange connection, the correct procedure is:", opts: ["Tighten bolts randomly to full torque","Apply lubricant to bolt threads and nut faces, then tighten in a cross-pattern (star pattern) in multiple passes to specified torque","Tighten bolts sequentially around the flange","Apply maximum torque in one pass"], ans: 1, exp: "Correct bolt make-up: (1) clean and lubricate threads and nut faces, (2) hand-tighten all bolts, (3) tighten in cross-pattern (180° apart) in 3-4 passes: 30%, 60%, 100% of final torque, (4) final pass at 100% torque. Cross-pattern ensures uniform gasket seating." },
    { q: "The purpose of 'pressure testing the annulus' after casing hanger installation is to:", opts: ["Test the casing string burst pressure","Verify the casing hanger seal integrity by pressurizing the annulus between casing strings and confirming no pressure communication"], ans: 1, exp: "Annulus pressure test verifies: (1) casing hanger seal is properly set and holding, (2) no communication between annuli (which would indicate seal failure), (3) compliance with well barrier requirements. Test pressure = typically 70% of casing burst or wellhead WP." },
    { q: "The 'anti-rotation pin' in a casing hanger serves to:", opts: ["Prevent the hanger from being retrieved","Prevent rotation of the hanger during make-up of the seal assembly, ensuring correct orientation of the seal and test ports","Provide additional load capacity","Connect to the running tool"], ans: 1, exp: "Anti-rotation pins prevent the casing hanger from rotating during seal assembly installation. Correct orientation is critical for: (1) alignment of test ports with wellhead test ports, (2) proper engagement of lockdown mechanisms, (3) correct seal energization." },
    { q: "Following a wellhead installation, the 'wellhead acceptance test' per API 6A requires:", opts: ["Visual inspection only","Hydrostatic body test at 1.5× WP and seat tests at WP with zero allowable leakage","Functional test of valves only","Documentation review only"], ans: 1, exp: "API 6A acceptance testing: (1) hydrostatic body test at 1.5× WP to verify structural integrity, (2) seat tests at rated WP with zero leakage, (3) function tests for all valves and actuators. All tests must be witnessed and documented." },
  ].map((q, i) => ({ moduleId: 30006, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30007 - Inspection and Monitoring
  ...[
    { q: "The recommended inspection interval for a wellhead Christmas tree in a sour service well per API 6A and industry practice is:", opts: ["Every 10 years","Annually or after any significant pressure event","Every 5 years","Monthly visual inspection only"], ans: 1, exp: "Sour service wellheads require annual inspection (or after significant events) due to accelerated corrosion from H2S and CO2. This includes: visual inspection, pressure testing of seals, valve function tests, and NDT of critical components." },
    { q: "Magnetic Particle Testing (MT) of wellhead components is limited to:", opts: ["All materials","Ferromagnetic materials (carbon steel, low-alloy steel) only","Non-ferromagnetic materials only","Plastic components only"], ans: 1, exp: "MT requires ferromagnetic materials (iron, nickel, cobalt alloys) to create the magnetic field. It cannot be used on austenitic stainless steel, aluminum, or non-metallic materials. PT (Penetrant Testing) is used for non-ferromagnetic materials." },
    { q: "Ultrasonic Testing (UT) of wellhead wall thickness is used to detect:", opts: ["Surface cracks only","Internal corrosion and wall thinning without removing the component from service","Leaks only","Material composition"], ans: 1, exp: "UT thickness measurement detects internal corrosion/erosion by measuring remaining wall thickness from the outside surface. This allows in-service inspection without disassembly, providing corrosion rate data for remaining life assessment." },
    { q: "The 'corrosion allowance' in wellhead design is typically:", opts: ["0 mm (no corrosion expected)","1-3 mm added to calculated minimum wall thickness to account for corrosion over design life","10% of wall thickness","Determined by operating pressure only"], ans: 1, exp: "Corrosion allowance (CA) = expected corrosion rate × design life. Typically 1-3 mm for sweet service, higher for sour/CO2 service. CA is added to the calculated minimum wall thickness to ensure adequate wall thickness throughout the design life." },
    { q: "A wellhead pressure gauge showing erratic readings may indicate:", opts: ["Normal pressure fluctuations","Gauge isolation valve partially closed, gauge diaphragm failure, or actual pressure instability in the well","Incorrect gauge range","Temperature effects only"], ans: 1, exp: "Erratic pressure readings require investigation: (1) check gauge isolation valve is fully open, (2) check for gauge diaphragm/bourdon tube failure, (3) check for plugged impulse line, (4) verify with a calibrated test gauge. If gauge is confirmed accurate, investigate well pressure instability." },
    { q: "The 'Christmas tree valve function test' requires verifying:", opts: ["Visual condition only","That each valve opens and closes fully, achieves rated pressure isolation, and operates within specified torque/force limits","Valve color coding only","Valve manufacturer's serial number"], ans: 1, exp: "Valve function test: (1) full open/close operation, (2) pressure test of closed valve at rated WP (zero leakage), (3) operating torque/force within API 6A limits, (4) stem packing integrity, (5) actuator function (if applicable). Documented in maintenance records." },
    { q: "Acoustic Emission Testing (AET) of pressurized wellhead components can detect:", opts: ["Wall thickness only","Active crack growth and leak detection under pressure by detecting stress wave emissions","Surface corrosion only","Material composition"], ans: 1, exp: "AET detects acoustic signals (stress waves) emitted by active defects under load: (1) active crack growth, (2) plastic deformation, (3) leak detection (fluid escaping through cracks). AET is unique in detecting ACTIVE (growing) defects, not just existing defects." },
    { q: "The inspection record for a wellhead should include as a minimum:", opts: ["Visual inspection results only","Equipment identification, inspection date, inspector qualifications, inspection method, findings, acceptance criteria, and corrective actions","Manufacturer's name only","Operating pressure at time of inspection"], ans: 1, exp: "Complete inspection records per API 6A and ISO 9001: (1) equipment ID/serial number, (2) inspection date and location, (3) inspector name and qualifications, (4) inspection method and procedure, (5) findings with measurements, (6) acceptance/rejection criteria, (7) corrective actions required/taken." },
    { q: "Dye Penetrant Testing (PT) of a wellhead component reveals a linear indication. The acceptance criterion per ASME Section V is:", opts: ["Linear indications up to 5mm are acceptable","Linear indications are NOT acceptable (rejectable) regardless of length","Linear indications up to 10mm are acceptable","Only indications >25mm are rejectable"], ans: 1, exp: "Per ASME Section V and most wellhead inspection codes, linear indications (length ≥ 3× width) are REJECTABLE regardless of length, as they indicate cracks or crack-like defects. Only rounded indications have length-based acceptance criteria." },
    { q: "The 'wellhead integrity management' program should trigger immediate action when:", opts: ["Any minor corrosion is detected","Annular pressure exceeds the maximum allowable annular surface pressure (MAASP) or sustained casing pressure is detected","Annual inspection is due","A new operator takes over"], ans: 1, exp: "Sustained Casing Pressure (SCP) or pressure exceeding MAASP indicates a barrier failure (seal, cement, or casing). This requires immediate investigation and remediation per well integrity management standards (NORSOK D-010, API RP 90) to prevent escalation to a blowout." },
  ].map((q, i) => ({ moduleId: 30007, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30008 - Maintenance Procedures
  ...[
    { q: "The recommended lubricant for wellhead gate valve stem threads and packing gland is:", opts: ["Any general-purpose grease","API 6A compliant lubricant compatible with wellbore fluids (H2S, CO2, hydrocarbons) and rated for operating temperature","WD-40 or similar penetrating oil","Petroleum jelly only"], ans: 1, exp: "Wellhead lubricants must be: (1) compatible with wellbore fluids (H2S, CO2, hydrocarbons, methanol), (2) rated for operating temperature range, (3) non-reactive with seal materials, (4) API 6A compliant. Using incompatible lubricants can cause seal swelling or degradation." },
    { q: "Valve packing replacement on a live wellhead valve (under pressure) requires:", opts: ["Depressurizing the well completely","Using the back-seat (valve fully open) to isolate the packing area, then replacing packing under controlled conditions","Replacing the entire valve","Waiting for scheduled shutdown only"], ans: 1, exp: "Live packing replacement procedure: (1) fully open valve to engage back-seat, (2) verify back-seat integrity (zero leakage past back-seat), (3) relieve packing gland pressure, (4) replace packing rings, (5) re-tighten gland, (6) test. Only possible if back-seat is leak-tight." },
    { q: "The torque required to operate a wellhead gate valve increases significantly when:", opts: ["Temperature decreases","Differential pressure across the gate increases (valve partially open under flow) or packing is over-tightened","Temperature increases","Flow rate decreases"], ans: 1, exp: "Operating torque increases with: (1) differential pressure across the gate (friction between gate and seats), (2) over-tightened packing (excessive stem friction), (3) corrosion/buildup on stem threads, (4) worn or damaged seats. Excessive torque indicates a maintenance problem." },
    { q: "Preventive maintenance (PM) for a wellhead Christmas tree typically includes:", opts: ["Replacement of all components annually","Valve function tests, lubrication of stems and threads, pressure testing of seals, visual inspection, and actuator testing at specified intervals","Visual inspection only","Replacement only when failure occurs"], ans: 1, exp: "PM program includes: (1) valve function tests (quarterly/annually), (2) stem lubrication (quarterly), (3) packing gland inspection and adjustment, (4) pressure testing of seals (annually), (5) actuator function test and hydraulic fluid check, (6) visual inspection for corrosion/damage." },
    { q: "When replacing a ring joint gasket on a wellhead flange, the ring groove must be:", opts: ["Left as-is","Cleaned, inspected for damage, and measured for dimensional compliance before installing the new ring","Coated with sealant","Lightly sanded to improve surface finish"], ans: 1, exp: "Ring groove preparation: (1) clean thoroughly (remove old ring, scale, corrosion), (2) inspect for scratches, pitting, out-of-roundness, (3) measure dimensions per API 6A tolerances, (4) repair minor damage with fine abrasive, (5) reject if damage exceeds limits. Never use sealant on ring joint connections." },
    { q: "The 'bonnet bolt' torque on a wellhead valve must be verified during maintenance because:", opts: ["It affects valve color","Insufficient torque allows bonnet leakage; excessive torque can distort the bonnet and affect valve operation","It determines valve flow rate","It affects valve pressure rating"], ans: 1, exp: "Bonnet bolts maintain the pressure-containing integrity of the valve body. Insufficient torque = bonnet leakage (external leak). Excessive torque = bonnet distortion, affecting gate/seat alignment and potentially causing internal leakage or difficult operation." },
    { q: "A wellhead valve that requires increasing force to operate over time (not due to pressure) most likely indicates:", opts: ["Normal wear","Corrosion or scale buildup on the stem threads or in the body cavity","Improved sealing","Temperature effects only"], ans: 1, exp: "Progressive increase in operating force (not pressure-related) indicates: (1) corrosion products on stem threads, (2) scale (carbonate, sulfate) buildup in body cavity, (3) packing swelling due to chemical incompatibility, (4) debris accumulation. Requires disassembly and cleaning." },
    { q: "The maintenance interval for wellhead hydraulic actuators should be based on:", opts: ["Calendar time only","Manufacturer's recommendations, number of operations, fluid analysis results, and inspection findings","Number of operations only","Cost considerations only"], ans: 1, exp: "Actuator maintenance intervals consider: (1) manufacturer's PM schedule, (2) number of operations (cycle count), (3) hydraulic fluid analysis (contamination, degradation), (4) inspection findings (seal condition, spring condition), (5) operating environment (temperature, H2S exposure)." },
    { q: "After completing maintenance on a wellhead component, the minimum required test before returning to service is:", opts: ["Visual inspection only","Pressure test at rated working pressure to verify seal integrity, documented in maintenance records","Function test only","Manufacturer's certificate review"], ans: 1, exp: "Post-maintenance pressure testing is mandatory: (1) pressure test at rated WP (or as specified in maintenance procedure), (2) zero leakage acceptance criterion, (3) test witnessed and documented, (4) return-to-service authorization by competent person. This verifies the maintenance was successful." },
    { q: "The 'mean time between failures' (MTBF) for wellhead valves is used in:", opts: ["Determining valve purchase price","Reliability-centered maintenance (RCM) to optimize maintenance intervals and spare parts inventory","Determining valve pressure rating","Regulatory reporting only"], ans: 1, exp: "MTBF data is used in RCM to: (1) set optimal maintenance intervals (not too frequent = unnecessary cost, not too infrequent = increased failure risk), (2) size spare parts inventory, (3) identify high-failure-rate components for redesign, (4) calculate system reliability and availability." },
  ].map((q, i) => ({ moduleId: 30008, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30009 - Troubleshooting
  ...[
    { q: "A wellhead master valve shows external leakage from the bonnet area. The immediate action should be:", opts: ["Increase valve operating pressure","Isolate the valve using the upstream valve, depressurize the bonnet area, and inspect/replace bonnet seals","Continue operating and monitor","Replace the entire Christmas tree"], ans: 1, exp: "External leakage from bonnet: (1) isolate using upstream valve (close lower master valve), (2) depressurize the leaking section, (3) inspect bonnet bolts (re-torque if loose), (4) if still leaking, replace bonnet seals. Never ignore external leakage - it is a well barrier failure." },
    { q: "Wellhead annular pressure buildup (APB) in a sealed annulus is confirmed by:", opts: ["Decreasing wellhead pressure","Pressure increase in the annulus when the well is shut in, with no communication to the wellbore or surface","Increasing production rate","Decreasing water cut"], ans: 1, exp: "APB confirmation: (1) pressure builds in sealed annulus during production (thermal expansion), (2) pressure decreases when well is shut in and cools, (3) no communication to wellbore (bleed-down test shows no flow), (4) pressure cycles with production/shutdown cycles." },
    { q: "A wellhead choke valve showing excessive erosion after 3 months of service indicates:", opts: ["Normal wear","Produced sand/solids content exceeding the design basis, requiring harder trim material (tungsten carbide) or sand management","Incorrect valve size","Insufficient operating pressure"], ans: 1, exp: "Rapid choke erosion indicates: (1) sand/solids production exceeding design basis, (2) incorrect trim material (use tungsten carbide or ceramic for high-sand service), (3) need for sand management (sand screens, gravel pack), (4) consider reducing flow rate to below erosional velocity." },
    { q: "A wellhead pressure gauge shows zero pressure when the well should be producing. The first diagnostic step is:", opts: ["Assume the well has died","Check if the gauge isolation valve is open and the impulse line is not plugged","Call for a workover immediately","Increase choke opening"], ans: 1, exp: "Systematic diagnosis: (1) verify gauge isolation valve is open, (2) check for plugged impulse line (hydrate, scale, wax), (3) verify with a portable test gauge, (4) check if other gauges on the tree show pressure, (5) only then investigate well performance issues." },
    { q: "A wellhead valve that cannot be fully closed (stops at 80% closed) is most likely caused by:", opts: ["Insufficient operating pressure","Foreign object (debris, scale) lodged in the valve body preventing full gate travel","Incorrect valve size","Normal wear"], ans: 1, exp: "Valve not fully closing: (1) debris/scale in valve body preventing gate travel, (2) bent or damaged gate, (3) damaged seat preventing gate seating, (4) actuator stroke limitation. Requires isolation, depressurization, and inspection. A valve that cannot fully close is a well barrier failure." },
    { q: "Sustained casing pressure (SCP) in the production casing annulus (A-annulus) indicates:", opts: ["Normal thermal effects","A leak in the production tubing, tubing hanger seal, or subsurface safety valve allowing wellbore pressure to communicate with the annulus","High production rate","Normal gas lift operation"], ans: 1, exp: "SCP in A-annulus indicates a barrier failure: (1) tubing leak (corrosion, erosion, connection failure), (2) tubing hanger seal failure, (3) SSSV seal failure, (4) packer failure. Requires investigation per well integrity management procedures (NORSOK D-010)." },
    { q: "A wellhead Christmas tree showing ice formation on the outside during winter operations indicates:", opts: ["Normal condensation","Joule-Thomson cooling from a small gas leak through a valve seat or fitting, causing localized cooling below the dew point","High production rate","Insulation failure only"], ans: 1, exp: "Ice/frost on wellhead components indicates: (1) gas leaking through a valve seat or fitting (J-T cooling causes freezing), (2) the leak may be too small to detect by other means. This is a safety concern - the leak must be located and repaired." },
    { q: "The 'bleed-down test' for a wellhead valve is performed to:", opts: ["Measure flow rate","Verify valve seat integrity by pressurizing upstream, closing the valve, then monitoring downstream pressure for increase (indicating leakage past the seat)","Test valve operating torque","Measure valve Cv"], ans: 1, exp: "Bleed-down test: (1) pressurize upstream side to test pressure, (2) close valve under test, (3) bleed down downstream side to zero, (4) monitor downstream pressure for 15-30 minutes. Any pressure increase = leakage past valve seat. Zero pressure rise = valve is leak-tight." },
    { q: "A wellhead hydraulic actuator that operates slowly (takes 3× normal time to open/close) is most likely caused by:", opts: ["Incorrect valve size","Hydraulic fluid contamination, low accumulator pre-charge pressure, or restriction in hydraulic lines","High operating pressure","Normal aging"], ans: 1, exp: "Slow actuator operation: (1) hydraulic fluid contamination (water, particles) causing viscosity increase or valve sticking, (2) low accumulator pre-charge (insufficient stored energy), (3) restriction in hydraulic lines (kinked hose, partially closed valve), (4) actuator seal wear increasing internal leakage." },
    { q: "Root cause analysis (RCA) of a wellhead seal failure should include:", opts: ["Identifying the failed component only","Identifying the failure mechanism, contributing factors, and systemic causes to prevent recurrence","Replacing the failed component only","Documenting the failure date only"], ans: 1, exp: "Effective RCA: (1) failure mechanism (corrosion, fatigue, overload, installation error), (2) contributing factors (material selection, operating conditions, maintenance practices), (3) systemic causes (design deficiency, procedure inadequacy, training gap), (4) corrective actions addressing root causes, not just symptoms." },
  ].map((q, i) => ({ moduleId: 30009, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30010 - Safety and HSE
  ...[
    { q: "The 'Permit to Work' (PTW) system for wellhead maintenance requires which minimum documentation?", opts: ["Verbal authorization only","Written permit specifying work scope, hazards, isolation measures, PPE requirements, emergency procedures, and authorized signatures","Equipment tag only","Supervisor's verbal approval"], ans: 1, exp: "PTW minimum requirements: (1) work description and location, (2) hazard identification (H2S, pressure, flammables), (3) isolation/LOTO measures, (4) PPE requirements, (5) emergency procedures and muster point, (6) gas testing requirements, (7) signatures of issuer, receiver, and area authority." },
    { q: "The IDLH (Immediately Dangerous to Life or Health) concentration of H2S is:", opts: ["1 ppm","10 ppm","100 ppm","1000 ppm"], ans: 2, exp: "NIOSH IDLH for H2S = 100 ppm. At this concentration, escape without respiratory protection becomes impossible within 30 minutes. OSHA PEL = 20 ppm ceiling; ACGIH TLV-TWA = 1 ppm; TLV-STEL = 5 ppm." },
    { q: "The LOTO (Lockout/Tagout) procedure for a wellhead valve requires:", opts: ["Tagging only","Closing the valve, applying a physical lock to prevent reopening, and verifying isolation by attempting to operate the valve and checking for zero energy","Verbal notification to coworkers","Reducing pressure only"], ans: 1, exp: "LOTO procedure: (1) notify affected employees, (2) shut down equipment, (3) isolate energy source (close valve), (4) apply lockout device (physical lock) to prevent re-opening, (5) release stored energy (bleed pressure), (6) verify isolation (attempt to open valve, check pressure gauge = zero)." },
    { q: "The minimum safe working distance from a wellhead during a pressure test at 15,000 psi is determined by:", opts: ["A fixed distance of 50 meters","Risk assessment considering potential energy release, fragment trajectory, and personnel exposure - typically defined in the test procedure","The length of the test hose","Regulatory requirement of 100 meters"], ans: 1, exp: "Safe distance for pressure testing is determined by risk assessment: (1) calculate potential energy stored in pressurized system, (2) assess fragment hazard from potential failure, (3) define exclusion zone based on fragment trajectory analysis. Typically 30-100m depending on volume and pressure." },
    { q: "A 'well control' incident at a wellhead is defined as:", opts: ["Any valve operation","An uncontrolled flow of formation fluids (kick or blowout) due to loss of primary well barrier integrity","Any pressure test failure","A routine production shutdown"], ans: 1, exp: "Well control incident = uncontrolled flow of formation fluids due to barrier failure. Levels: (1) kick = influx detected and controlled, (2) blowout = uncontrolled surface flow. Prevention requires maintaining two independent well barriers per NORSOK D-010 and API RP 100." },
    { q: "The required H2S monitor alarm setpoints for personnel working on wellheads in sour service are typically:", opts: ["Single alarm at 100 ppm","Low alarm at 5-10 ppm (warning), high alarm at 20-25 ppm (evacuate), IDLH alarm at 100 ppm","Single alarm at 50 ppm","No alarm required if wearing SCBA"], ans: 1, exp: "H2S monitor alarm levels: (1) low alarm 5-10 ppm = warning, check wind direction, prepare to evacuate, (2) high alarm 20-25 ppm = evacuate to muster point, (3) IDLH alarm 100 ppm = immediate evacuation with SCBA. All personnel must be trained in response procedures." },
    { q: "The 'two-man rule' for wellhead operations in H2S service means:", opts: ["Two people must sign the permit","No person should work alone in an H2S hazard area - a second person must be present and able to assist in emergency","Two supervisors must approve the work","Two permits are required"], ans: 1, exp: "The two-man rule (buddy system) requires a second person to: (1) monitor the worker for signs of H2S exposure, (2) call for help if the worker is incapacitated, (3) provide rescue assistance (without entering the hazard zone without SCBA). Critical for H2S areas where rapid incapacitation can occur." },
    { q: "Emergency shutdown (ESD) testing of wellhead safety valves must verify:", opts: ["Visual condition only","That the valve closes within the specified time (typically <30 seconds) and achieves leak-tight closure when the ESD signal is activated","That the valve opens correctly","Annual documentation only"], ans: 1, exp: "ESD valve testing: (1) activate ESD signal, (2) verify valve closes within specified time (typically <30 seconds per API 14C), (3) pressure test closed valve to verify leak-tight closure, (4) verify ESD signal is received and logged, (5) restore valve to normal position and verify. Document all results." },
    { q: "The 'safety case' for a wellhead facility must demonstrate:", opts: ["That the facility is profitable","That all major accident hazards have been identified, their risks assessed, and reduced to ALARP with adequate emergency response arrangements","That the facility meets production targets","That all equipment is new"], ans: 1, exp: "Safety case (per UK PFEER/COMAH regulations and similar): (1) hazard identification (HAZID, HAZOP), (2) risk assessment (QRA), (3) demonstration that risks are ALARP, (4) major accident event (MAE) prevention measures, (5) emergency response arrangements, (6) management system for maintaining safety." },
    { q: "The 'fire triangle' for wellhead fires requires fuel, oxygen, and heat. The most effective primary prevention measure for wellhead fires is:", opts: ["Having fire extinguishers nearby","Preventing ignition sources in areas where flammable gas/liquid may be present (hot work permits, ATEX equipment, static elimination)","Increasing water deluge capacity","Training firefighters"], ans: 1, exp: "Primary fire prevention = eliminating ignition sources: (1) hot work permits for all spark-producing activities, (2) ATEX-rated electrical equipment in hazardous areas, (3) static elimination (bonding/grounding), (4) no smoking policies, (5) vehicle exclusion zones. Secondary prevention = detection and suppression." },
  ].map((q, i) => ({ moduleId: 30010, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30011 - Corrosion and Materials
  ...[
    { q: "NACE MR0175/ISO 15156 applies to which service condition?", opts: ["High-temperature service","Sour service (H2S-containing environments) to prevent sulfide stress cracking (SSC) of metallic materials","High-pressure service","Offshore service only"], ans: 1, exp: "NACE MR0175/ISO 15156 specifies requirements for metallic materials used in oil and gas production equipment in H2S-containing environments to prevent SSC, stress corrosion cracking (SCC), and hydrogen-induced cracking (HIC)." },
    { q: "The critical H2S partial pressure threshold above which SSC (Sulfide Stress Cracking) risk is significant per NACE MR0175 is:", opts: ["0.05 psia","0.5 psia","5 psia","50 psia"], ans: 0, exp: "Per NACE MR0175/ISO 15156, the threshold for sour service is H2S partial pressure >0.05 psia (0.34 kPa) in gas phase, or >0.05 psia in the gas cap of a multiphase system. Below this, standard materials may be used." },
    { q: "CO2 corrosion (sweet corrosion) in wellhead equipment produces which primary corrosion product?", opts: ["Iron oxide (rust)","Iron carbonate (FeCO3) - siderite scale","Iron sulfide (FeS)","Calcium carbonate (CaCO3)"], ans: 1, exp: "CO2 dissolves in water to form carbonic acid (H2CO3), which attacks steel. The primary corrosion product is iron carbonate (FeCO3, siderite). At temperatures >60°C, FeCO3 forms a protective scale; below 60°C, the scale is porous and non-protective." },
    { q: "The de Waard-Milliams model is used to predict:", opts: ["H2S corrosion rates","CO2 corrosion rates in oil and gas production systems","Erosion rates","Galvanic corrosion rates"], ans: 1, exp: "The de Waard-Milliams (1975) model predicts CO2 corrosion rates as a function of CO2 partial pressure and temperature. It is the most widely used model for sweet corrosion prediction in oil and gas systems." },
    { q: "Galvanic corrosion between a carbon steel wellhead and a stainless steel valve will preferentially corrode:", opts: ["The stainless steel (more noble)","The carbon steel (less noble/more active in the galvanic series)","Both equally","Neither, if properly isolated"], ans: 1, exp: "In a galvanic couple, the less noble (more active) metal corrodes preferentially. Carbon steel is less noble than stainless steel in the galvanic series. The carbon steel becomes the anode and corrodes; the stainless steel is the cathode and is protected." },
    { q: "The 'erosion-corrosion' mechanism in wellhead choke valves is accelerated by:", opts: ["Low flow velocity","High velocity of sand-laden fluids combined with corrosive species (CO2, H2S, chlorides)","Low temperature","High viscosity fluids"], ans: 1, exp: "Erosion-corrosion synergy: (1) erosion removes the protective corrosion product film, (2) corrosion attacks the fresh metal surface, (3) the combined rate exceeds the sum of individual rates. Accelerated by: high velocity, sand/solids, turbulence, corrosive species." },
    { q: "Duplex stainless steel (e.g., 22Cr, 25Cr) is selected for wellhead components in sour service because:", opts: ["Lower cost than carbon steel","Superior resistance to both SSC and pitting corrosion compared to austenitic stainless steel, while meeting NACE MR0175 hardness limits","Higher strength only","Better weldability"], ans: 1, exp: "Duplex SS advantages: (1) high resistance to pitting and crevice corrosion (high PREN), (2) resistance to SSC when hardness is controlled per NACE MR0175 (max 36 HRC), (3) higher strength than austenitic SS (allows thinner walls), (4) good resistance to CO2 and Cl- corrosion." },
    { q: "The 'pitting resistance equivalent number' (PREN) for stainless steel is calculated as:", opts: ["PREN = %Cr + %Ni","PREN = %Cr + 3.3×%Mo + 16×%N","PREN = %Cr + %Mo","PREN = %Ni + %Mo"], ans: 1, exp: "PREN = %Cr + 3.3×%Mo + 16×%N. Higher PREN = better pitting resistance. Minimum PREN for seawater service: >40 (duplex SS), >45 (super duplex SS). Carbon steel PREN ≈ 0." },
    { q: "Microbiologically Influenced Corrosion (MIC) in wellhead systems is most effectively controlled by:", opts: ["Increasing operating pressure","Biocide injection combined with regular pigging/cleaning to remove biofilm","Increasing temperature","Reducing flow rate"], ans: 1, exp: "MIC control: (1) biocide injection (oxidizing: chlorine, ClO2; non-oxidizing: glutaraldehyde, THPS) to kill bacteria, (2) regular pigging/cleaning to remove biofilm and deposits where bacteria thrive, (3) oxygen exclusion (SRB require anaerobic conditions). Biocide alone is insufficient without biofilm removal." },
    { q: "The hardness limit for carbon steel components in sour service per NACE MR0175 is:", opts: ["22 HRC maximum","22 HRC maximum (equivalent to 248 HV or 237 HBN)","35 HRC maximum","No hardness limit"], ans: 1, exp: "NACE MR0175/ISO 15156 limits carbon and low-alloy steel hardness to 22 HRC maximum (248 HV, 237 HBN) for sour service. Higher hardness increases susceptibility to SSC. Heat treatment (PWHT, tempering) is required to achieve and verify this limit." },
  ].map((q, i) => ({ moduleId: 30011, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),

  // Module 30012 - Workover and Intervention
  ...[
    { q: "The primary purpose of a Blowout Preventer (BOP) stack during wellhead workover is:", opts: ["To measure wellbore pressure","To provide well control by sealing the wellbore annulus or full bore in the event of an unexpected influx (kick)","To support the weight of the drill string","To direct drilling fluid flow"], ans: 1, exp: "BOP stack functions: (1) annular preventer seals around any tubular or open hole, (2) pipe rams seal around specific pipe sizes, (3) blind/shear rams close and cut the pipe for emergency well shut-in. The BOP is the primary well control barrier during workover." },
    { q: "In coiled tubing (CT) operations on a live wellhead, the 'stripper' assembly is used to:", opts: ["Remove scale from the tubing","Provide a pressure seal around the moving CT while allowing it to be run in and out of the well under pressure","Measure CT weight","Connect CT to the wellhead"], ans: 1, exp: "The CT stripper (or stuffing box) provides a dynamic pressure seal around the moving coiled tubing, allowing CT to be run in and out of the well while maintaining wellbore pressure containment. It is a critical well barrier during CT operations." },
    { q: "The 'kill weight mud' for a workover operation is calculated as:", opts: ["Current mud weight","Mud weight = (Shut-in casing pressure / 0.052 / TVD) + current mud weight","Mud weight = formation pressure / TVD","Mud weight = 10 ppg always"], ans: 1, exp: "Kill mud weight = (SICP / 0.052 / TVD) + current mud weight. Where SICP = shut-in casing pressure (psi), TVD = true vertical depth (ft). This provides sufficient hydrostatic pressure to balance formation pressure and kill the well." },
    { q: "Wireline operations on a wellhead use a 'lubricator' assembly to:", opts: ["Lubricate the wireline","Provide a pressure-containing chamber above the wellhead to allow tools to be run in and out of the well under pressure","Measure wireline tension","Connect the wireline to the wellhead"], ans: 1, exp: "The lubricator is a pressure-containing tube (typically 20-40 ft long) installed above the Christmas tree. Tools are loaded into the lubricator, which is then pressurized to wellbore pressure before opening the tree valve, allowing tools to be run into the well without pressure loss." },
    { q: "The 'snubbing' operation is required when:", opts: ["The well is dead (no pressure)","The upward force from wellbore pressure on the pipe string exceeds the string weight, requiring hydraulic force to push the pipe into the well","The well needs to be killed","The wellhead needs replacement"], ans: 1, exp: "Snubbing is required when wellbore pressure × pipe cross-sectional area > pipe string weight (pipe is 'light'). A hydraulic snubbing unit provides the force to push the pipe into the well against the pressure. Critical for live well interventions with small-diameter tubing." },
    { q: "The 'bullheading' well kill method involves:", opts: ["Pumping kill fluid down the annulus","Pumping kill fluid down the tubing at high rate to force wellbore fluids back into the formation without circulating","Circulating kill fluid through the drill string","Using coiled tubing to pump kill fluid"], ans: 1, exp: "Bullheading = pumping kill fluid (brine, mud) down the tubing at high rate to force wellbore fluids (gas, oil) back into the formation. Used when: (1) circulation is not possible, (2) rapid well kill is required, (3) gas has migrated to surface. Risk: formation damage from forcing fluids into reservoir." },
    { q: "In a wellhead workover requiring Christmas tree removal, the minimum well barrier requirement per NORSOK D-010 is:", opts: ["One mechanical barrier","Two independent, tested well barriers must be in place before removing the Christmas tree","Three barriers","No specific requirement"], ans: 1, exp: "NORSOK D-010 (and API RP 100) requires TWO independent, tested well barriers before removing any primary well barrier (Christmas tree). Typically: (1) tubing plug or SSSV, (2) tubing hanger plug or packer. Both must be pressure tested before tree removal." },
    { q: "The 'formation damage' risk during workover operations is minimized by:", opts: ["Using maximum pump rate","Using completion fluids compatible with formation water and reservoir rock (no swelling clays, no precipitation), and minimizing overbalance","Using high-density mud","Maximizing fluid invasion"], ans: 1, exp: "Formation damage prevention: (1) use completion fluids with matching salinity to prevent clay swelling, (2) avoid fluids that precipitate with formation water (scale), (3) minimize overbalance pressure to reduce fluid invasion, (4) use temporary bridging agents for fluid loss control." },
    { q: "The 'tree isolation valve' (TIV) or 'tree cap valve' is installed during workover to:", opts: ["Increase production rate","Provide an additional barrier above the Christmas tree during tree removal/installation, preventing wellbore fluids from escaping","Measure wellbore pressure","Support the BOP stack"], ans: 1, exp: "The TIV/tree cap valve is installed on top of the Christmas tree before removal operations. It provides an additional pressure barrier, allowing the tree to be removed while maintaining well control. It is removed after the new tree is installed and tested." },
    { q: "Post-workover well testing must verify:", opts: ["That the well produces at maximum rate","Wellbore integrity (no tubing leaks), wellhead integrity (all seals and valves), and production performance (compared to pre-workover baseline)","Only production rate","Only wellhead pressure"], ans: 1, exp: "Post-workover testing: (1) tubing pressure test (verify no leaks), (2) wellhead pressure test (all seals and valves), (3) production test (compare to pre-workover to verify workover objective was achieved), (4) annulus pressure monitoring (verify no communication), (5) documentation of all results." },
  ].map((q, i) => ({ moduleId: 30012, questionTextEn: q.q, options: q.opts.map((t,j)=>({id:['a','b','c','d'][j],textEn:t})), correctOptionId: ['a','b','c','d'][q.ans], explanationEn: q.exp, order: i+1 })),
];

// ============================================================
// COURSE FINAL EXAM QUESTIONS
// ============================================================

// Helper to create MCQ question
const mcq = (courseId, q, opts, ans, exp, order) => ({
  courseId, questionType: 'mcq', questionTextEn: q,
  options: opts.map((t,j) => ({id:['a','b','c','d'][j], textEn:t})),
  correctOptionId: ['a','b','c','d'][ans], explanationEn: exp,
  difficulty: 'expert', timeLimitSeconds: 90, order
});

// Helper to create True/False question
const tf = (courseId, q, ans, exp, order) => ({
  courseId, questionType: 'true_false', questionTextEn: q,
  options: [{id:'T', textEn:'True'}, {id:'F', textEn:'False'}],
  correctOptionId: ans ? 'T' : 'F', explanationEn: exp,
  difficulty: 'hard', timeLimitSeconds: 60, order
});

const epfFinalQuestions = [
  // MCQ Questions (70 questions)
  mcq(1,"In an EPF design, the 'turndown ratio' refers to:",["The ratio of design pressure to operating pressure","The minimum operable flow rate as a percentage of design capacity","The ratio of gas to liquid processing capacity","The ratio of capital cost to operating cost"],1,"Turndown ratio = minimum stable operating flow rate / design capacity. Typical EPF turndown = 20-30% of design. Below turndown, equipment (separators, pumps) cannot operate stably.",1),
  mcq(1,"The 'shrinkage factor' in oil production accounting represents:",["Oil lost to evaporation","The volume reduction from reservoir conditions to stock tank conditions due to gas liberation and temperature/pressure changes","The oil retained in pipelines","The measurement uncertainty"],1,"Shrinkage factor = Stock Tank Volume / Reservoir Volume. Typically 0.7-0.9 for volatile oils, 0.9-0.98 for black oils. Used to convert reservoir barrels to stock tank barrels for production accounting.",2),
  mcq(1,"Which separator configuration is most efficient for handling foamy crude oil?",["Vertical two-phase separator","Horizontal three-phase separator with anti-foam baffles and extended residence time","Spherical separator","Cyclone separator"],1,"Foamy crude requires: (1) horizontal orientation for maximum liquid surface area, (2) anti-foam baffles to break foam, (3) extended residence time (2-3× normal), (4) anti-foam chemical injection. Vertical separators have limited liquid surface area for foam breaking.",3),
  mcq(1,"The 'flash point' of stabilized crude oil is important for:",["Reservoir characterization","Transportation and storage safety classification (flammable vs combustible liquid)","Refinery processing","Well completion design"],1,"Flash point determines safety classification: <60°C = flammable liquid (Class I), >60°C = combustible liquid. Export crude typically requires flash point >60°C for safe tanker loading and storage. Stabilization raises flash point by removing light ends.",4),
  mcq(1,"In a gas dehydration unit, the 'glycol circulation rate' is typically expressed as:",["Liters per hour","Gallons of glycol per pound of water absorbed (gal/lb H2O)","Kilograms per day","Moles per hour"],1,"Glycol circulation rate = gallons of lean glycol per pound of water absorbed. Typical TEG rate = 2-4 gal/lb H2O. Higher rates improve dehydration but increase energy consumption and glycol losses.",5),
  mcq(1,"The 'water dew point' specification for pipeline gas export is typically:",["0°C at operating pressure","-10°C to -20°C at maximum operating pressure","Ambient temperature","No specification required"],1,"Pipeline gas water dew point specifications: typically -10°C to -20°C at maximum operating pressure to prevent liquid water formation (corrosion, hydrate formation) in the pipeline. Offshore pipelines may require -20°C to -30°C.",6),
  mcq(1,"In crude oil stabilization, the 'true vapor pressure' (TVP) differs from RVP because:",["TVP is measured at 100°F; RVP is at 60°F","TVP is the actual vapor pressure at storage temperature; RVP is a standardized test at 100°F with a 4:1 vapor-liquid ratio","TVP includes dissolved gases; RVP does not","TVP is for gas; RVP is for liquid"],1,"TVP = actual vapor pressure at storage temperature. RVP = standardized test (ASTM D323) at 100°F with 4:1 V/L ratio. TVP is used for actual storage and transport conditions; RVP is used for specification and comparison purposes.",7),
  mcq(1,"The 'produced water to oil ratio' (WOR) in a mature field typically:",["Decreases over time","Increases over field life as water influx increases","Remains constant","Increases then decreases"],1,"WOR increases over field life as: (1) aquifer influx increases, (2) water injection breaks through, (3) reservoir pressure maintenance by water injection. WOR can reach 10:1 or higher in mature fields, making water handling the dominant design constraint.",8),
  mcq(1,"The 'gas-oil ratio' (GOR) in a solution gas drive reservoir will:",["Remain constant throughout production","Increase as reservoir pressure drops below bubble point (dissolved gas comes out of solution)","Decrease over time","Increase then decrease"],1,"In solution gas drive: (1) above bubble point: GOR = initial GOR (constant), (2) below bubble point: free gas forms, GOR increases as gas expands and flows preferentially, (3) late depletion: GOR may decrease as gas cap depletes.",9),
  mcq(1,"The 'OPEX' for an EPF facility typically includes all EXCEPT:",["Chemical costs","Equipment depreciation (which is CAPEX amortization, not OPEX)","Maintenance labor","Utilities (fuel, power, water)"],1,"OPEX = ongoing costs to operate the facility: chemicals, maintenance, labor, utilities, insurance, regulatory fees. Depreciation is an accounting treatment of CAPEX, not an operational expense. CAPEX = one-time capital investment.",10),
  mcq(1,"In a three-phase separator, the 'oil pad' thickness is controlled by:",["The gas outlet pressure","The oil weir height or interface level controller","The water outlet valve","The inlet diverter"],1,"Oil pad thickness = distance between water-oil interface and oil weir (or oil outlet). Controlled by: (1) fixed weir height (simple), (2) interface level controller (LIC) on water outlet (more precise). Insufficient oil pad = water carryover in oil; excessive = oil carryover in water.",11),
  mcq(1,"The 'recycle ratio' in a gas compression system refers to:",["The ratio of recycled gas to total gas processed","The fraction of compressed gas returned to the suction to control flow rate and prevent surge","The ratio of fuel gas to produced gas","The compression ratio"],1,"Recycle ratio = recycle flow / total compressor throughput. Anti-surge recycle maintains minimum flow through the compressor to prevent surge (unstable operation). Higher recycle = more energy wasted but better surge protection.",12),
  mcq(1,"Which chemical is most commonly used for H2S scavenging in EPF gas streams?",["Methanol","Triazine (hexahydro-1,3,5-tris(2-hydroxyethyl)-s-triazine)","Monoethylene glycol (MEG)","Sodium hydroxide"],1,"Triazine-based scavengers react irreversibly with H2S to form non-hazardous products. Used for low-to-moderate H2S concentrations (<100 ppm) where amine treating is uneconomical. Methanol is a hydrate inhibitor, not H2S scavenger.",13),
  mcq(1,"The 'first-stage separator' pressure in a multi-stage separation system is optimized to:",["Maximize gas production","Maximize liquid recovery (minimize shrinkage) while meeting downstream pressure requirements","Minimize equipment size","Maximize water separation"],1,"First-stage pressure optimization: too high = insufficient gas liberation (high RVP), too low = excessive gas production (liquid shrinkage). Optimal pressure maximizes stock tank liquid recovery. Typically 100-500 psig for first stage.",14),
  mcq(1,"In EPF design, the 'design basis' document must specify:",["Only equipment sizes","Fluid compositions, flow rates, operating conditions, design conditions, utility requirements, and applicable codes and standards","Only safety requirements","Only environmental requirements"],1,"Design basis = foundation document specifying all fluid compositions (GOR, WOR, BS&W, H2S, CO2), flow rates (min/normal/max), operating conditions, design conditions (pressure, temperature), utility requirements, and applicable codes (API, ASME, NACE, IEC).",15),
  mcq(1,"The 'pressure drop' across a wellhead choke valve operating in critical (sonic) flow is characterized by:",["Downstream pressure affects flow rate","Flow rate is independent of downstream pressure (controlled only by upstream pressure and choke size)","Upstream pressure does not affect flow rate","Flow rate is proportional to pressure drop"],1,"Critical (sonic) flow: gas velocity at the choke throat reaches sonic velocity. Flow rate depends only on upstream pressure and choke size - downstream pressure has NO effect. This simplifies production control and measurement.",16),
  mcq(1,"In EPF produced water treatment, the 'oil-in-water' (OiW) concentration is measured by:",["Visual inspection","Gas chromatography (GC) or infrared spectroscopy (IR) methods per ISO 9377-2 or EPA 1664","Simple settling test","pH measurement"],1,"OiW measurement methods: (1) GC/FID (ISO 9377-2): measures total petroleum hydrocarbons, (2) IR spectroscopy (EPA 1664): measures extractable hydrocarbons, (3) UV fluorescence: rapid screening. Regulatory compliance requires certified laboratory methods.",17),
  mcq(1,"The 'heat exchanger fouling factor' (Rf) in crude oil service is typically:",["Zero (no fouling expected)","0.0002 hr·ft²·°F/BTU for crude oil per TEMA standards","0.01 hr·ft²·°F/BTU","0.1 hr·ft²·°F/BTU"],1,"TEMA fouling factors: crude oil = 0.0002 hr·ft²·°F/BTU (0.000035 m²·K/W). Fouling reduces heat transfer efficiency and must be included in heat exchanger design. Actual fouling depends on crude composition, temperature, and velocity.",18),
  mcq(1,"The 'net positive suction head required' (NPSHr) for a centrifugal pump must be compared to NPSHa to prevent:",["Excessive flow rate","Cavitation (vapor bubble formation and collapse) which causes noise, vibration, and impeller damage","Motor overload","Seal failure"],1,"Cavitation occurs when local pressure drops below vapor pressure, forming vapor bubbles that collapse violently. NPSHa (available) must exceed NPSHr (required) by a safety margin (typically 1.0-1.5m). Cavitation causes impeller erosion and pump failure.",19),
  mcq(1,"In EPF gas compression, the 'interstage cooling' between compression stages is required to:",["Increase compression ratio","Remove heat of compression to reduce gas volume and protect downstream equipment from high temperature","Increase gas pressure","Remove water from gas"],1,"Interstage cooling: (1) removes heat of compression (gas temperature rises during compression), (2) reduces gas volume entering next stage (improving efficiency), (3) protects compressor seals and valves from high temperature, (4) condenses and removes water/hydrocarbons.",20),
  mcq(1,"The 'API gravity' of a crude oil mixture of 60% light crude (40°API) and 40% heavy crude (20°API) is approximately:",["32°API","30°API","28°API","35°API"],0,"Blended API gravity = weighted average: (0.6 × 40) + (0.4 × 20) = 24 + 8 = 32°API. Note: this is an approximation; exact calculation requires blending by specific gravity, not API gravity directly.",21),
  mcq(1,"The 'minimum ignition energy' (MIE) for methane-air mixtures is approximately:",["0.3 mJ","25 mJ","100 mJ","1000 mJ"],0,"MIE for methane = ~0.3 mJ. This extremely low energy means static electricity from clothing, tools, or equipment can ignite methane-air mixtures. This drives the requirement for ATEX equipment and anti-static measures in gas processing facilities.",22),
  mcq(1,"In EPF design, the 'process safety time' (PST) is defined as:",["Time to complete a shutdown","The maximum time from detection of a hazardous condition to when the process reaches a safe state before a dangerous situation develops","Time between safety valve tests","Time to evacuate personnel"],1,"PST = time available from hazard detection to dangerous condition development. Safety instrumented systems (SIS) must respond within PST. PST determines the required response time for safety functions and SIL requirements.",23),
  mcq(1,"The 'lower explosive limit' (LEL) of natural gas (primarily methane) in air is approximately:",["1%","5%","10%","15%"],1,"LEL of methane = 5% by volume in air. UEL = 15%. Gas detectors typically alarm at 10-20% LEL (0.5-1.0% methane) to provide early warning well before explosive concentrations are reached.",24),
  mcq(1,"In EPF operations, 'line heaters' (indirect water bath heaters) are used primarily to:",["Heat crude oil for separation","Prevent hydrate formation in gas streams by heating gas above the hydrate formation temperature","Generate steam for utilities","Heat produced water for treatment"],1,"Line heaters heat gas streams (wellhead gas, gas from separators) above the hydrate formation temperature before pressure reduction (chokes, regulators). They prevent hydrate blockages in gas lines and equipment.",25),
  mcq(1,"The 'slug catcher' in an EPF receiving pipeline fluids is designed to:",["Remove sand from the pipeline","Handle large liquid slugs (accumulated liquid in pipeline low points) without overloading downstream separators","Measure flow rate","Reduce pipeline pressure"],1,"Slug catchers handle intermittent large liquid slugs from pipelines (caused by terrain, pigging, startup). They provide surge capacity to dampen slug flow before it reaches separators, preventing liquid carryover and process upsets.",26),
  mcq(1,"The 'specific gravity' of a gas mixture with molecular weight of 25 g/mol (air MW = 29 g/mol) is:",["0.862","1.16","0.5","2.0"],0,"Gas specific gravity = MW_gas / MW_air = 25 / 29 = 0.862. SG < 1 means gas is lighter than air (rises and disperses). SG > 1 means gas is heavier than air (accumulates in low points - more hazardous).",27),
  mcq(1,"In EPF water injection systems, the 'injection pressure' must exceed:",["Reservoir pore pressure only","Reservoir pore pressure + formation fracture pressure safety margin (to avoid fracturing the formation unintentionally)","Surface pipeline pressure only","Pump discharge pressure"],0,"Injection pressure must exceed reservoir pore pressure to inject water but must stay below fracture pressure to avoid unintentional hydraulic fracturing (which can cause loss of injection zone integrity and water breakthrough to producers).",28),
  mcq(1,"The 'wellhead flowing temperature' is important for EPF design because it affects:",["Only wellhead pressure","Fluid viscosity, phase behavior, hydrate formation potential, and heat exchanger sizing throughout the facility","Only separator sizing","Only pump selection"],1,"Flowing temperature affects: (1) oil viscosity (lower T = higher viscosity = higher pump power), (2) phase behavior (GOR, water content), (3) hydrate formation potential, (4) heat exchanger duty, (5) wax deposition potential. It is a fundamental design parameter.",29),
  mcq(1,"In EPF fiscal metering, the 'meter factor' is determined by:",["Manufacturer's calibration only","Proving the meter against a calibrated prover (pipe prover or master meter) at actual operating conditions","Calculation from fluid properties","Regulatory tables"],1,"Meter factor (MF) = Prover volume / Meter indicated volume. Determined by proving at actual conditions (flow rate, temperature, pressure, fluid composition). MF corrects for meter inaccuracies. API MPMS Chapter 4 specifies proving procedures.",30),
  mcq(1,"The 'gas compression ratio' per stage in a multistage compressor is typically limited to:",["2:1","4:1","10:1","20:1"],1,"Compression ratio per stage is limited to ~4:1 (sometimes 3:1 for reciprocating, up to 5:1 for centrifugal) to control: (1) discharge temperature (T2 = T1 × r^((k-1)/k)), (2) rod loads for reciprocating compressors, (3) mechanical stress. Multiple stages with intercooling achieve higher overall ratios.",31),
  mcq(1,"The 'Wobbe number' is used to characterize fuel gas interchangeability. A gas with Wobbe number 1350 BTU/scf can replace a gas with Wobbe number 1300 BTU/scf without burner adjustment because:",["They have the same heating value","They deliver the same thermal input at the same pressure drop (within ±5% interchangeability limit)","They have the same specific gravity","They have the same composition"],1,"Gases are interchangeable if their Wobbe numbers are within ±5% of each other. Same Wobbe number = same thermal input at same pressure drop, regardless of composition differences. This is the fundamental interchangeability criterion.",32),
  mcq(1,"In EPF design, the 'process hazard analysis' (PHA) must be completed:",["After construction","Before detailed engineering to influence design, not just document existing design","During commissioning","After startup"],1,"PHA (HAZOP, HAZID, What-If) must be completed before detailed engineering to: (1) identify hazards early when design changes are inexpensive, (2) influence equipment selection and layout, (3) define safety instrumented system requirements. Late PHAs only document problems, not prevent them.",33),
  mcq(1,"The 'atmospheric emissions' from an EPF that require environmental permits typically include:",["Only CO2","Flare emissions (CO2, NOx, SO2, unburned hydrocarbons), fugitive emissions from equipment, and storage tank breathing losses","Only H2S","Only noise"],1,"Regulated atmospheric emissions: (1) flare: CO2, NOx, SO2 (from H2S), particulates, unburned hydrocarbons, (2) fugitive: equipment leaks (valves, flanges, seals), (3) storage: tank breathing losses, (4) combustion: engines, heaters. Environmental permits specify limits and monitoring requirements.",34),
  mcq(1,"The 'isentropic efficiency' of a gas expander (turboexpander) is typically:",["50-60%","75-85%","90-95%","99%"],1,"Turboexpander isentropic efficiency = 75-85% for typical oil and gas applications. This means 75-85% of the theoretical isentropic work is actually extracted. The remaining energy goes to heat (irreversibilities). Higher efficiency = more cooling for NGL recovery.",35),
  mcq(1,"In EPF crude oil storage, the 'working capacity' of a tank is:",["The total geometric volume","Total volume minus the dead volume (below outlet nozzle) and the vapor space required for thermal expansion","The maximum fill volume","The emergency reserve volume"],1,"Working capacity = total volume - dead volume (below outlet) - vapor space (for thermal expansion and safety). Typically 80-85% of geometric volume. The remaining volume provides safety margin and prevents overflow during thermal expansion.",36),
  mcq(1,"The 'PSSR' (Pre-Startup Safety Review) for an EPF must verify:",["Only equipment installation","That all safety systems are functional, procedures are in place, personnel are trained, and the facility is safe to introduce hydrocarbons","Only process conditions","Only regulatory approvals"],1,"PSSR (also called PSSR or Pre-commissioning Safety Review) verifies before hydrocarbon introduction: (1) all safety systems functional (ESD, F&G, relief), (2) procedures written and approved, (3) personnel trained, (4) regulatory permits obtained, (5) emergency response ready.",37),
  mcq(1,"The 'bubble point pressure' of a reservoir oil sample at 150°F is 2500 psia. If the current reservoir pressure is 3500 psia, the oil is:",["Saturated (at bubble point)","Undersaturated (above bubble point) - single phase liquid","Two-phase (oil + gas)","At critical conditions"],1,"Undersaturated oil: reservoir pressure (3500 psia) > bubble point (2500 psia). The oil is a single-phase liquid with all gas dissolved. No free gas exists in the reservoir. Production above bubble point maintains single-phase flow.",38),
  mcq(1,"In EPF design, 'plot plan optimization' considers all EXCEPT:",["Prevailing wind direction for flare and vent placement","Equipment color preferences","Safety distances between equipment","Maintenance access requirements"],1,"Plot plan optimization: (1) prevailing wind for flare/vent placement (downwind of personnel areas), (2) safety distances (API 505, IP 15), (3) maintenance access (crane paths, equipment removal), (4) process flow logic, (5) utility routing. Equipment color is a minor aesthetic consideration, not a design driver.",39),
  mcq(1,"The 'FEED' (Front End Engineering Design) phase of an EPF project delivers:",["Detailed engineering drawings","Sufficient engineering definition (±10-15% cost estimate, key equipment specifications, plot plan) to support a final investment decision (FID)","Construction drawings","Commissioning procedures"],1,"FEED deliverables: (1) ±10-15% capital cost estimate, (2) key equipment datasheets and specifications, (3) plot plan, (4) P&IDs (60-90% complete), (5) hazard studies (HAZOP), (6) environmental impact assessment, (7) project execution plan. FEED supports the FID.",40),
  // True/False questions (30 questions)
  tf(1,"In a two-phase separator, increasing the operating pressure always improves liquid-gas separation efficiency.",false,"Higher pressure increases gas density, reducing the density difference between gas and liquid, which can actually reduce separation efficiency. The optimal pressure depends on the fluid system and separator design.",41),
  tf(1,"The Joule-Thomson effect causes natural gas to cool when its pressure is reduced through a valve.",true,"Natural gas at pipeline conditions has a positive Joule-Thomson coefficient: it cools when pressure drops isenthalpically through a restriction. This cooling can cause hydrate formation or condensation.",42),
  tf(1,"A crude oil with API gravity of 45° is classified as heavy crude.",false,"API gravity >31.1° = light crude. API 22-31.1° = medium crude. API 10-22° = heavy crude. API <10° = extra-heavy crude. 45°API is light crude.",43),
  tf(1,"The 'critical flow' condition through a wellhead choke valve means that downstream pressure changes do not affect the flow rate.",true,"In critical (sonic) flow, the gas velocity at the choke throat equals the speed of sound. Downstream pressure disturbances cannot propagate upstream past the sonic point, so downstream pressure has no effect on flow rate.",44),
  tf(1,"TEG (Triethylene Glycol) dehydration can achieve water dew points below -100°C.",false,"TEG dehydration achieves water dew points of -20°C to -40°C at best (with stripping gas). For ultra-deep dehydration (<-60°C), molecular sieves are required. LNG plants require <-100°C, achievable only with molecular sieves.",45),
  tf(1,"In a three-phase separator, the oil-water interface level is always above the gas-oil interface level.",false,"In a three-phase separator, gas is at the top, oil in the middle, and water at the bottom. The gas-oil interface is ABOVE the oil-water interface. The oil forms a layer between the gas and water.",46),
  tf(1,"Hydrogen sulfide (H2S) is heavier than air and accumulates in low-lying areas.",true,"H2S molecular weight = 34 g/mol vs air = 29 g/mol. Specific gravity = 1.19 (heavier than air). H2S accumulates in pits, trenches, cellars, and low points, creating lethal concentrations that are not dispersed by natural ventilation.",47),
  tf(1,"The 'flash point' of a liquid is the temperature at which it spontaneously ignites without an external ignition source.",false,"Flash point = minimum temperature at which vapors ignite with an external ignition source (spark or flame). Auto-ignition temperature (AIT) = temperature at which spontaneous ignition occurs without external source. Flash point < AIT.",48),
  tf(1,"In EPF design, the design pressure of a vessel must always equal the maximum operating pressure.",false,"Design pressure = operating pressure + 10% (or +25 psi, whichever is greater) per ASME VIII. This provides margin for pressure surges and control upsets. Design pressure > operating pressure.",49),
  tf(1,"A centrifugal pump operating to the left of its best efficiency point (BEP) on the performance curve experiences increased vibration and reduced reliability.",true,"Operating left of BEP (low flow): (1) increased recirculation in impeller, (2) increased vibration and noise, (3) higher temperature rise, (4) reduced bearing and seal life. Pumps should operate within 70-110% of BEP flow for reliable operation.",50),
  tf(1,"In gas compression, the 'surge' condition occurs when the compressor operates at too high a flow rate.",false,"Surge occurs at TOO LOW flow rate (not high). At low flow, the pressure ratio the compressor can develop drops below the system pressure, causing reverse flow. Surge causes violent pressure oscillations and can damage the compressor.",51),
  tf(1,"The 'bubble point' and 'dew point' of a pure component are identical.",true,"For a pure component, the bubble point (first bubble of gas forms) and dew point (first drop of liquid forms) occur at the same pressure and temperature - this is the vapor pressure curve. Only mixtures have a two-phase envelope between bubble and dew point curves.",52),
  tf(1,"In EPF produced water treatment, a hydrocyclone can remove dissolved salts from produced water.",false,"Hydrocyclones remove dispersed oil droplets and suspended solids by centrifugal force. They CANNOT remove dissolved salts (ions in solution). Dissolved salt removal requires ion exchange, reverse osmosis, or thermal desalination.",53),
  tf(1,"The 'net heating value' (NHV or LHV) of a fuel is always higher than the 'gross heating value' (GHV or HHV).",false,"GHV (HHV) > NHV (LHV). GHV includes the heat of condensation of water vapor in combustion products. NHV excludes this (assumes water leaves as vapor). GHV = NHV + latent heat of water condensation.",54),
  tf(1,"In EPF design, the 'safety instrumented system' (SIS) must be independent of the basic process control system (BPCS).",true,"IEC 61511 requires SIS independence from BPCS: separate sensors, logic solvers, and final elements. This ensures that a BPCS failure does not simultaneously defeat the SIS. Independence is fundamental to achieving the required SIL.",55),
  tf(1,"Crude oil with high asphaltene content is more prone to emulsion formation than crude with low asphaltene content.",true,"Asphaltenes are natural surfactants that stabilize water-in-oil emulsions by adsorbing at the water-oil interface and forming a rigid interfacial film. High asphaltene content = more stable emulsions = more difficult dehydration.",56),
  tf(1,"The 'cricondenbar' is the maximum temperature at which two phases can coexist in a hydrocarbon mixture.",false,"Cricondenbar = maximum PRESSURE at which two phases can coexist. Cricondentherm = maximum TEMPERATURE at which two phases can coexist. Above the cricondentherm, only single-phase gas exists regardless of pressure.",57),
  tf(1,"In EPF operations, a 'pressure safety valve' (PSV) is designed to open at the set pressure and remain open until the pressure drops significantly below the set pressure.",false,"PSVs open at set pressure and close when pressure drops to the 'blowdown' pressure, typically 5-10% below set pressure. This 'blowdown' prevents chattering (rapid opening/closing). The valve does not remain open indefinitely.",58),
  tf(1,"The 'turndown ratio' of a control valve is the ratio of maximum to minimum controllable flow rate.",true,"Turndown ratio = Cv_max / Cv_min = maximum controllable flow / minimum controllable flow. Typical control valves: 50:1 turndown. This means the valve can control flow from 2% to 100% of maximum. Higher turndown = more flexible control.",59),
  tf(1,"In EPF gas dehydration, increasing the lean TEG temperature entering the contactor improves water absorption efficiency.",false,"Higher lean TEG temperature REDUCES water absorption efficiency. TEG absorbs water more effectively at lower temperatures (equilibrium favors absorption at lower T). Lean TEG is typically cooled before entering the contactor to maximize absorption.",60),
  tf(1,"The 'mean time to repair' (MTTR) is a measure of equipment reliability.",false,"MTTR measures MAINTAINABILITY (how quickly equipment can be repaired), not reliability. MTBF (Mean Time Between Failures) measures reliability. Availability = MTBF / (MTBF + MTTR).",61),
  tf(1,"In EPF crude oil measurement, the 'shrinkage factor' is always less than 1.0.",true,"Shrinkage factor = stock tank volume / reservoir volume. Since reservoir oil shrinks when pressure and temperature decrease (gas comes out of solution, thermal contraction), the stock tank volume is always less than reservoir volume. Shrinkage factor < 1.0.",62),
  tf(1,"A 'pig' in pipeline operations is used exclusively for cleaning the pipeline interior.",false,"Pipeline pigs are used for multiple purposes: (1) cleaning (foam pigs, brush pigs), (2) inspection (intelligent/smart pigs with MFL, UT sensors), (3) gauging (caliper pigs), (4) liquid displacement (batching pigs), (5) chemical application. Cleaning is just one function.",63),
  tf(1,"In EPF design, the 'pressure vessel' classification per ASME Section VIII applies only to vessels operating above 15 psig.",true,"ASME Section VIII Div. 1 applies to pressure vessels with design pressure >15 psig (103 kPa). Vessels at ≤15 psig are not covered by ASME VIII and may be designed to other standards (API 650 for atmospheric storage tanks).",64),
  tf(1,"The 'flash gas' from a crude oil stabilizer can always be used directly as fuel gas without treatment.",false,"Flash gas from stabilizers may contain: (1) H2S (must be removed for fuel gas), (2) CO2 (reduces heating value), (3) heavy hydrocarbons (condensation in fuel lines), (4) water vapor (corrosion, hydrates). Treatment may be required depending on composition.",65),
  tf(1,"In EPF water injection systems, the injection water must be oxygen-free to prevent corrosion and bacterial growth.",true,"Dissolved oxygen in injection water causes: (1) severe corrosion of carbon steel injection lines and wellbore, (2) promotes growth of aerobic bacteria, (3) reacts with H2S to form elemental sulfur (plugging). Oxygen removal (<10 ppb) by vacuum deaeration or chemical scavenging is essential.",66),
  tf(1,"The 'process flow diagram' (PFD) and 'piping and instrumentation diagram' (P&ID) contain the same level of detail.",false,"PFD shows major equipment, process streams, and operating conditions - high level overview. P&ID shows all equipment, all instruments (with tag numbers), all control loops, all valves (including manual), and all piping details. P&ID has much more detail than PFD.",67),
  tf(1,"In EPF operations, 'hot work' includes any work that generates sparks, flames, or heat sufficient to ignite flammable materials.",true,"Hot work = any work that generates ignition sources: welding, cutting, grinding, brazing, soldering, use of non-ATEX power tools, internal combustion engines. Requires hot work permit, gas testing, fire watch, and isolation of flammable materials.",68),
  tf(1,"The 'relief valve' and 'safety valve' are interchangeable terms for the same device.",false,"Safety valve: spring-loaded, opens fully and quickly (pop action) - used for gas/vapor service. Relief valve: opens proportionally to overpressure - used for liquid service. Safety relief valve: can be used for both. The terms are NOT interchangeable per API 520/521.",69),
  tf(1,"In EPF design, the 'inherently safer design' (ISD) principle prioritizes administrative controls over engineering controls.",false,"ISD hierarchy: (1) Eliminate hazard (best), (2) Substitute with less hazardous material/process, (3) Moderate (reduce quantity/conditions), (4) Simplify (reduce complexity). Engineering controls (inherent) are preferred over administrative controls (procedures, training) which are less reliable.",70),
];

const wellheadFinalQuestions = [
  // MCQ Questions (70 questions)
  mcq(2,"The 'wellhead load' on the surface casing includes all EXCEPT:",["Weight of all casing strings hung in the wellhead","Weight of the Christmas tree and BOP stack during drilling","Weight of the production tubing string","Weight of the reservoir fluids in the wellbore"],3,"Wellhead structural loads: (1) casing string weights (all strings hung in wellhead), (2) Christmas tree weight, (3) BOP stack weight (during drilling), (4) tubing string weight, (5) thermal loads, (6) wind/seismic loads. Reservoir fluid weight is supported by the formation/casing, not the wellhead.",1),
  mcq(2,"The 'annular safety valve' (ASV) in a wellhead is designed to:",["Control production flow rate","Provide isolation of the casing annulus to prevent uncontrolled flow from the annulus to surface in case of tubing failure","Measure annular pressure","Connect the annulus to the flare system"],1,"ASV (or CASV - Casing Annulus Safety Valve) closes the casing annulus in case of tubing failure or other emergency, preventing uncontrolled flow from the annulus. Required in some jurisdictions for high-pressure or sour service wells.",2),
  mcq(2,"The 'wellhead growth' (thermal expansion) of a wellhead during production heating must be accommodated by:",["Rigid connections only","Flexible connections (expansion spools, flexible jumpers) or by designing the wellhead and flowline to accommodate the expected thermal movement","Welding all connections","Reducing production temperature"],1,"Wellhead thermal growth: production heats the wellhead, causing upward movement (thermal expansion of casing strings). Flowline connections must accommodate this movement via: (1) expansion spools, (2) flexible jumpers, (3) designed flexibility in the piping system.",3),
  mcq(2,"In API 6A, the 'product specification level' (PSL) 1, 2, 3, 3G, and 4 define:",["Pressure ratings","Manufacturing quality requirements, testing, and documentation levels - higher PSL = more rigorous requirements","Material grades","Temperature classes"],1,"PSL defines manufacturing quality: PSL 1 = basic (minimal testing), PSL 2 = intermediate (more NDE, impact testing), PSL 3 = high (full NDE, material traceability), PSL 3G = PSL 3 + gas test, PSL 4 = highest (all PSL 3G + additional requirements for critical service).",4),
  mcq(2,"The 'casing burst' failure mode occurs when:",["External pressure exceeds internal pressure","Internal pressure exceeds the casing burst rating (yield strength × wall thickness / radius)","Axial tension exceeds yield strength","Torque exceeds torsional yield"],1,"Casing burst: internal pressure > burst rating. Burst rating = 0.875 × 2 × yield × wall thickness / OD (API 5C3). The 0.875 factor accounts for manufacturing tolerance (12.5% wall thickness variation). Burst is the governing failure mode for high-pressure wells.",5),
  mcq(2,"The 'wellhead pressure integrity test' (WPIT) is performed to:",["Measure production rate","Verify the integrity of all wellhead seals and barriers after installation or maintenance, using pressure testing at rated working pressure","Test valve actuators only","Measure wellbore temperature"],1,"WPIT verifies: (1) all seals (ring joints, casing hanger seals, tubing hanger seals) at rated WP, (2) all valve seats at rated WP, (3) zero leakage acceptance criterion, (4) documented and witnessed. Performed after installation, maintenance, and at regular intervals.",6),
  mcq(2,"The 'master valve' in a Christmas tree is positioned:",["At the top of the tree","Directly above the tubing head/wellhead, as the primary isolation valve for the production bore","In the flowline","Below the wellhead"],1,"The master valve (lower master valve, LMV) is the first valve above the tubing head, providing primary isolation of the production bore. The upper master valve (UMV) provides secondary isolation. The wing valve controls flow to the flowline.",7),
  mcq(2,"In a wellhead with 'dual barriers' per NORSOK D-010, the barriers are:",["Two gate valves in series","Two independent, tested pressure barriers - typically the primary completion (tubing/packer) and the wellhead/Christmas tree","Two check valves","The wellhead and the BOP"],1,"NORSOK D-010 well barriers: Barrier 1 (primary) = tubing string + packer + SSSV. Barrier 2 (secondary) = wellhead + Christmas tree + wellhead seals. Both must be independent, tested, and documented. Loss of either barrier requires immediate investigation.",8),
  mcq(2,"The 'Christmas tree orientation' (vertical vs horizontal) is selected based on:",["Operator preference only","Well type (vertical tree for land/platform wells; horizontal tree for subsea or space-constrained applications), and maintenance access requirements","Cost only","Pressure rating only"],1,"Vertical trees: standard for land and platform wells, easy access for maintenance. Horizontal trees: used for subsea (lower profile, easier ROV access), HPHT wells (shorter flow path), and space-constrained platforms. Selection based on application and maintenance requirements.",9),
  mcq(2,"The 'wellhead connector' torque specification is critical because:",["It affects flow rate","Insufficient torque causes seal leakage; excessive torque can yield the connector bolts or distort the sealing surfaces","It determines pressure rating","It affects temperature rating"],1,"Connector torque: (1) insufficient = inadequate gasket seating stress = leakage, (2) excessive = bolt yielding, gasket extrusion, flange distortion = leakage or structural failure. API 6A specifies torque values based on bolt size, grade, and lubrication.",10),
  mcq(2,"The 'flow coupling' installed above and below the SSSV (Subsurface Safety Valve) is designed to:",["Increase flow rate","Protect the tubing above and below the SSSV from erosion caused by turbulent flow through the valve","Measure flow rate","Provide additional isolation"],1,"Flow couplings are heavy-wall tubing joints installed above and below the SSSV. The SSSV creates turbulence when opening/closing, causing erosion of adjacent tubing. Flow couplings provide additional wall thickness to resist this erosion.",11),
  mcq(2,"In wellhead pressure testing, the 'bleed-off' rate after pressurizing to test pressure should be:",["As fast as possible","Controlled and slow to prevent water hammer and hydraulic shock to seals and connections","Instantaneous","Not required"],1,"Controlled bleed-off prevents: (1) water hammer (pressure waves from rapid depressurization), (2) hydraulic shock to seals, (3) cavitation in liquid-filled systems. Bleed-off rate typically limited to prevent pressure drop rate exceeding 100 psi/minute for sensitive seals.",12),
  mcq(2,"The 'wellhead flange face finish' for ring joint connections per API 6A requires:",["Smooth mirror finish","Specific serrated finish (125-250 μin Ra) to provide mechanical interlock with the ring gasket","Rough machined finish","Painted finish"],0,"Ring joint grooves require a specific surface finish: 63 μin Ra (1.6 μm) for the groove contact surfaces per API 6A. Too smooth = insufficient mechanical interlock; too rough = leak paths. The groove geometry (angle, width, depth) is also critical.",13),
  mcq(2,"The 'wellhead load capacity' must account for which combination of loads?",["Weight only","Weight (dead load) + pressure loads + thermal loads + dynamic loads (wind, seismic, slug flow) + fatigue loads","Pressure only","Weight + pressure only"],1,"Wellhead structural design must consider all loads: (1) dead loads (equipment weight), (2) pressure loads (internal pressure on cross-sectional areas), (3) thermal loads (expansion/contraction), (4) dynamic loads (wind, seismic, slug flow, wave loads offshore), (5) fatigue (cyclic loads).",14),
  mcq(2,"The 'wellhead tree cap' pressure test verifies:",["The tree cap weight","The integrity of the tree cap seal against the UMV (upper master valve) outlet, confirming the secondary barrier above the UMV","The tree cap material","The tree cap installation torque"],1,"Tree cap pressure test: (1) install tree cap on UMV outlet, (2) pressurize through test port to rated WP, (3) verify zero leakage at cap seal, (4) confirms secondary barrier integrity above UMV. Critical for well barrier verification.",15),
  mcq(2,"In a wellhead Christmas tree, the 'kill wing valve' (KWV) is used for:",["Normal production control","Pumping kill fluid into the well during workover or emergency well kill operations","Gas lift injection","Chemical injection"],1,"KWV provides access to the wellbore for: (1) pumping kill fluid (brine, mud) during workover, (2) emergency well kill, (3) pressure testing from the kill side. It is normally closed during production and opened only for well intervention.",16),
  mcq(2,"The 'wellhead elevation' above grade is specified to:",["Improve aesthetics","Provide access for maintenance, prevent flooding of wellhead equipment, and facilitate pigging operations","Reduce wind loads","Increase pressure rating"],1,"Wellhead elevation considerations: (1) maintenance access (valve operation, gauge reading), (2) flood protection (above 100-year flood level), (3) pigging access (pig launcher/receiver alignment), (4) drainage (prevent water accumulation), (5) safety (personnel access).",17),
  mcq(2,"The 'wellhead back pressure' effect on reservoir production rate is described by:",["Darcy's law only","The inflow performance relationship (IPR) and vertical lift performance (VLP) - the wellhead pressure is the boundary condition for VLP","Bernoulli's equation only","The continuity equation"],1,"Production system analysis: IPR describes reservoir inflow (Pwf vs rate). VLP describes wellbore hydraulics (Pwf vs rate for given wellhead pressure). The intersection of IPR and VLP = operating point. Wellhead pressure is the upper boundary condition for VLP.",18),
  mcq(2,"In API 6A, the 'material class' designation for equipment intended for H2S service with CO2 present is:",["Material Class AA","Material Class EE (H2S + CO2 service)","Material Class BB","Material Class CC"],1,"API 6A Material Classes for sour service: DD (H2S service), EE (H2S + CO2 service), FF (H2S + CO2 + chloride service), HH (H2S service with higher temperature). EE is specifically for combined H2S and CO2 environments.",19),
  mcq(2,"The 'wellhead orientation' (azimuth of the flowline connection) is important because:",["It affects pressure rating","It determines the direction of thermal growth and must align with the flowline routing to minimize bending loads on the wellhead","It affects material selection","It affects valve type selection"],1,"Wellhead orientation: the flowline connection direction must align with the flowline routing. Misalignment causes bending moments on the wellhead flange. Thermal growth of the wellhead must be accommodated by the flowline design (expansion loops, flexible connections).",20),
  mcq(2,"The 'wellhead pressure gauge' isolation valve should be:",["Always open","Normally open (to monitor wellhead pressure continuously) with the ability to close for gauge maintenance/replacement","Always closed","Opened only during testing"],1,"Gauge isolation valve: normally OPEN to provide continuous pressure monitoring (critical for well integrity and operations). Closed only for: (1) gauge replacement, (2) gauge calibration, (3) maintenance. Continuous pressure monitoring is essential for early detection of well integrity issues.",21),
  mcq(2,"In a wellhead with a 'downhole safety valve' (DHSV), the hydraulic control line failure mode is:",["Valve opens (fail open)","Valve closes (fail safe closed) - spring force closes valve when hydraulic pressure is lost","Valve stays in last position","Valve opens partially"],1,"DHSV is fail-safe closed: hydraulic pressure keeps valve open against spring force. Loss of hydraulic pressure (line failure, emergency) causes spring to close valve, providing downhole well barrier. This is the fundamental safety design of all SSSSVs.",22),
  mcq(2,"The 'wellhead completion fluid' used during tubing installation must be compatible with:",["Only the tubing material","Formation water, tubing material, wellhead seals, and reservoir rock (no formation damage)","Only the wellhead seals","Only the reservoir rock"],1,"Completion fluid compatibility: (1) formation water (no precipitation/scale), (2) reservoir rock (no clay swelling, no emulsion blocking), (3) tubing material (no corrosion), (4) wellhead seals (no swelling/degradation of elastomers), (5) SSSV (no plugging of control line).",23),
  mcq(2,"The 'wellhead Christmas tree' is typically rated for a design life of:",["1-2 years","20-25 years (matching the expected field life)","5-10 years","50+ years"],1,"Christmas tree design life = field design life, typically 20-25 years. This drives: (1) material selection (corrosion allowance), (2) seal material selection (temperature/chemical resistance over life), (3) maintenance planning, (4) spare parts inventory.",24),
  mcq(2,"In wellhead design, the 'wellbore schematic' is used to:",["Show surface equipment only","Document all downhole equipment (casing strings, tubing, packers, SSSV, perforations) and their depths, providing the basis for wellhead design","Show the Christmas tree only","Show the flowline routing"],1,"Wellbore schematic: (1) all casing strings (sizes, grades, depths, cement tops), (2) tubing string (size, grade, depth), (3) downhole equipment (packer, SSSV, gas lift mandrels), (4) perforations, (5) fluid contacts. Basis for wellhead design (hanger sizes, pressure ratings, seal selection).",25),
  mcq(2,"The 'wellhead flange bolt material' for sour service per NACE MR0175 must be:",["Standard carbon steel (ASTM A193 B7)","Low-alloy steel with controlled hardness (ASTM A193 B7M - maximum 235 HBN) or other NACE-compliant material","Stainless steel only","Titanium only"],1,"NACE MR0175 limits bolt hardness to prevent SSC: ASTM A193 B7M (max 235 HBN, 22 HRC) is the standard sour service bolt material. Standard B7 (max 321 HBN, 35 HRC) is NOT acceptable for sour service due to SSC risk.",26),
  mcq(2,"The 'wellhead pressure test' after a flange make-up must be performed:",["Only visually","With the appropriate test medium (water for hydrostatic, gas for gas test) at the specified test pressure, with zero leakage acceptance","With compressed air only","At 50% of working pressure only"],1,"Post-makeup pressure test: (1) use specified test medium (water preferred for safety, gas for final verification), (2) test pressure = rated WP for seat tests, 1.5×WP for body tests, (3) zero leakage acceptance, (4) hold time per API 6A, (5) document and witness.",27),
  mcq(2,"In wellhead operations, 'simultaneous operations' (SIMOPS) refers to:",["Normal production operations","Concurrent activities (e.g., drilling on one well while producing from adjacent wells) that require special risk assessment and coordination","Maintenance activities","Emergency response"],1,"SIMOPS = concurrent operations with potential interactions: (1) drilling + production, (2) workover + production, (3) construction + operations. Requires: SIMOPS risk assessment, coordination procedures, communication protocols, and clear authority matrix to manage interaction risks.",28),
  mcq(2,"The 'wellhead control panel' (WHCP) for a subsea well provides:",["Only pressure monitoring","Hydraulic and/or electrical control of subsea valves (SSSV, tree valves) and monitoring of wellhead parameters (pressure, temperature, position)","Only temperature monitoring","Only flow rate measurement"],1,"WHCP functions: (1) hydraulic control of SSSV and tree valves, (2) electrical control of actuators, (3) monitoring of wellhead pressure, temperature, valve positions, (4) ESD activation, (5) chemical injection control. Critical interface between surface operators and subsea wellhead.",29),
  mcq(2,"The 'wellhead abandonment' procedure per API RP 100 requires:",["Simply closing all valves","Permanent plugging of the wellbore with cement plugs, cutting and capping the casing at or below mudline (offshore), and removal of all surface equipment","Only removing the Christmas tree","Only closing the master valve"],1,"Well abandonment: (1) set cement plugs to isolate all hydrocarbon zones, (2) verify plug integrity by pressure testing, (3) cut and cap casing at mudline (offshore) or below grade (onshore), (4) remove all surface equipment, (5) restore site. Permanent abandonment must prevent future leakage to surface or groundwater.",30),
  mcq(2,"The 'wellhead Christmas tree' valve arrangement from bottom to top in a standard configuration is:",["Wing valve - Master valve - Swab valve","Lower master valve - Upper master valve - Wing valve - Swab valve","Swab valve - Wing valve - Master valve","Wing valve - Swab valve - Master valve"],1,"Standard Christmas tree valve arrangement (bottom to top): (1) Lower Master Valve (LMV) - primary isolation, (2) Upper Master Valve (UMV) - secondary isolation, (3) Wing Valve - controls flow to flowline, (4) Swab Valve - provides access for wireline/coiled tubing. Kill wing valve is on the opposite side from the production wing.",31),
  mcq(2,"The 'wellhead erosion' from sand production is most severe at:",["Straight pipe sections","Changes in flow direction (elbows, choke valves, tees) where sand particles impact the wall at high velocity","Long straight runs","Low-velocity sections"],1,"Erosion is most severe at: (1) choke valves (high velocity + direction change), (2) elbows (direction change), (3) tees, (4) reducers. Erosion rate ∝ velocity² × sand concentration × particle hardness. Erosion-resistant materials (tungsten carbide, ceramic) are used in high-erosion locations.",32),
  mcq(2,"The 'wellhead pressure relief valve' (PRV) set pressure must be:",["Equal to operating pressure","At or below the MAWP (Maximum Allowable Working Pressure) of the protected equipment","Above the MAWP","Equal to design pressure"],1,"PRV set pressure ≤ MAWP of protected equipment. The PRV must open before pressure exceeds MAWP. Set pressure is typically 90-100% of MAWP. If set pressure > MAWP, the equipment can be overpressured before the PRV opens.",33),
  mcq(2,"In wellhead design, the 'design factor' for casing connections per API 5C3 is:",["1.0 (no safety factor)","0.875 (accounts for 12.5% manufacturing wall thickness tolerance)","2.0","1.5"],1,"API 5C3 design factor = 0.875 for burst calculations, accounting for the allowed -12.5% wall thickness manufacturing tolerance. This means the minimum actual wall thickness = 0.875 × nominal wall thickness. The burst rating is calculated using this minimum wall.",34),
  mcq(2,"The 'wellhead tree valve' actuator sizing must account for:",["Only valve weight","Differential pressure across the valve, stem friction, packing friction, and safety factor - ensuring the actuator can operate the valve under worst-case conditions","Only spring force","Only valve size"],1,"Actuator sizing: (1) valve operating torque/force at maximum differential pressure, (2) stem packing friction, (3) spring force (for fail-safe actuators), (4) safety factor (typically 1.25-1.5×), (5) operating speed requirement. Undersized actuators fail to operate valves under emergency conditions.",35),
  mcq(2,"The 'wellhead Christmas tree' is typically manufactured from which base material?",["Austenitic stainless steel (316L)","Low-alloy steel (AISI 4130 or 4140) with appropriate heat treatment","Carbon steel (A105)","Duplex stainless steel only"],1,"Christmas tree bodies are typically AISI 4130 or 4140 low-alloy steel, heat treated to achieve required strength and toughness. For sour service, hardness is controlled per NACE MR0175 (max 22 HRC). Stainless steel is used for trim and sealing surfaces.",36),
  mcq(2,"The 'wellhead pressure transducer' calibration frequency is typically:",["Every 10 years","Annually or per manufacturer's recommendation, with calibration records maintained","Monthly","Only when readings appear incorrect"],1,"Pressure transducer calibration: (1) annual calibration against traceable standard, (2) calibration records with as-found and as-left readings, (3) calibration certificate, (4) more frequent calibration for fiscal metering instruments. Calibration drift can lead to incorrect well management decisions.",37),
  mcq(2,"The 'wellhead completion' sequence for a gas well with a downhole safety valve (DHSV) is:",["Install DHSV last","Run tubing with DHSV at specified depth, land tubing hanger, set DHSV control line, install Christmas tree, function test DHSV","Install Christmas tree first","Install packer last"],1,"Completion sequence: (1) run tubing string with DHSV at specified depth, (2) land tubing hanger in wellhead, (3) connect DHSV hydraulic control line to wellhead control port, (4) install Christmas tree, (5) function test DHSV (open/close, pressure test), (6) pressure test all wellhead seals.",38),
  mcq(2,"The 'wellhead flow cross' (or 'flow tee') in a Christmas tree is the component that:",["Controls flow rate","Provides the connection point for the production flowline and kill line, directing flow from the tubing bore to the flowline","Measures flow rate","Provides the swab valve connection"],1,"The flow cross (or flow tee) is the horizontal component of the Christmas tree that: (1) provides production wing valve connection (to flowline), (2) provides kill wing valve connection (for well kill), (3) may include chemical injection points, (4) connects to the upper master valve above and lower master valve below.",39),
  mcq(2,"In wellhead integrity management, 'sustained casing pressure' (SCP) is defined as:",["Normal annular pressure from gas lift","Pressure in a casing annulus that rebuilds after bleed-down, indicating a leak from the wellbore or from a higher-pressure annulus","Pressure from thermal expansion only","Normal wellhead pressure"],1,"SCP = pressure that rebuilds in a casing annulus after bleed-down. Indicates: (1) tubing leak, (2) packer failure, (3) casing connection leak, (4) cement failure. SCP is a well integrity concern requiring investigation per API RP 90 and NORSOK D-010.",40),
  mcq(2,"The 'wellhead Christmas tree' for a high-temperature geothermal well (>200°C) requires:",["Standard API 6A materials","Special high-temperature alloys (Inconel, Hastelloy) and metal seals, as standard elastomers and carbon steel cannot withstand these temperatures","Standard carbon steel with insulation","Plastic components"],1,"Geothermal wellheads >200°C require: (1) high-temperature alloys (Inconel 625, Hastelloy C-276) for corrosion resistance, (2) metal-to-metal seals (elastomers fail above 175°C), (3) special lubricants, (4) thermal insulation to protect actuators. Standard API 6A materials are insufficient.",41),
  // True/False questions (30 questions)
  tf(2,"The 'wellhead casing head housing' (CHH) is always welded to the conductor casing.",false,"CHH can be welded OR threaded to the conductor casing, depending on well design and operator preference. Welded connections provide higher structural integrity; threaded connections allow easier removal. Both are acceptable per API 6A.",42),
  tf(2,"A wellhead rated at 5000 psi working pressure can be used at 6000 psi operating pressure if the actual fluid is less corrosive than the design fluid.",false,"Working pressure rating is an absolute limit, not adjustable based on fluid properties. Operating pressure must NEVER exceed the rated working pressure. Using equipment above its rated WP is unsafe and violates API 6A.",43),
  tf(2,"The 'back pressure valve' (BPV) installed in the tubing hanger provides a downhole barrier during Christmas tree installation.",true,"The BPV is a check valve installed in the tubing hanger bore before Christmas tree installation. It prevents wellbore fluids from flowing to surface during tree installation, providing a temporary downhole barrier. Removed after tree is installed and tested.",44),
  tf(2,"In a wellhead Christmas tree, the 'swab valve' is used for normal production flow control.",false,"The swab valve is NOT used for production flow control. It provides access to the wellbore for wireline, coiled tubing, and other intervention operations. Production flow is controlled by the wing valve and choke. The swab valve is normally closed.",45),
  tf(2,"Wellhead flange bolts should be lubricated before installation to achieve accurate torque-tension relationship.",true,"Lubrication is essential for accurate torque-tension relationship: (1) reduces friction variability, (2) allows consistent bolt preload for given torque, (3) prevents galling (thread seizure), (4) facilitates future disassembly. Dry bolts require 25-40% more torque for same preload.",46),
  tf(2,"The 'wellhead Christmas tree' can be installed before the tubing hanger is landed.",false,"Installation sequence: (1) run and land tubing string, (2) land tubing hanger in wellhead, (3) set and test tubing hanger seals, (4) THEN install Christmas tree. The tree connects to the tubing hanger - it cannot be installed first.",47),
  tf(2,"Subsea wellhead connectors use hydraulic actuation for connection and disconnection to allow ROV operation.",true,"Subsea wellhead connectors (e.g., Cameron HC, Vetco Gray H-4) use hydraulic actuation for: (1) connection (setting the connector), (2) disconnection (releasing), (3) lock/unlock operations. All operations are designed for ROV tooling, as diver access is limited in deep water.",48),
  tf(2,"The 'wellhead Christmas tree' pressure rating must equal or exceed the maximum anticipated shut-in wellhead pressure (SIWHP).",true,"Christmas tree WP ≥ SIWHP (maximum shut-in wellhead pressure). SIWHP = reservoir pressure - hydrostatic head of wellbore fluid. The tree must contain the well under all conditions including full shut-in with no wellbore fluid column.",49),
  tf(2,"In wellhead maintenance, a gate valve can be used as a throttling device to control flow rate.",false,"Gate valves are designed for full-open or full-closed service ONLY. Throttling (partial opening) causes: (1) erosion of gate and seats, (2) vibration, (3) premature failure. Globe valves, needle valves, or choke valves are used for throttling.",50),
  tf(2,"The 'wellhead casing annulus' pressure monitoring is required only for high-pressure wells (>5000 psi).",false,"Annulus pressure monitoring is required for ALL wells, regardless of pressure rating. Annular pressure buildup or sustained casing pressure can indicate well integrity issues (barrier failure) at any pressure level. API RP 90 recommends monitoring all annuli.",51),
  tf(2,"The 'wellhead Christmas tree' can be safely removed from a well without any downhole barriers in place.",false,"NORSOK D-010 and API RP 100 require TWO independent, tested well barriers before removing the Christmas tree (a primary well barrier). Removing the tree without barriers creates an uncontrolled well - a blowout risk.",52),
  tf(2,"In API 6A, the 'ring joint' gasket material must be softer than the flange groove material to achieve a proper seal.",true,"Ring joint sealing principle: the ring (softer material) deforms plastically to conform to the groove (harder material), creating an intimate metal-to-metal contact. If the ring is harder than the groove, the groove deforms instead, damaging the flange.",53),
  tf(2,"The 'wellhead Christmas tree' wing valve is normally in the OPEN position during production.",true,"The wing valve controls flow from the wellbore to the production flowline. During normal production, the wing valve is OPEN (and the choke downstream controls the flow rate). The wing valve is closed for well shut-in or maintenance.",54),
  tf(2,"Wellhead equipment manufactured to API 6A PSL 4 requires 100% volumetric NDE (non-destructive examination) of all pressure-containing components.",true,"PSL 4 requires: (1) 100% volumetric NDE (RT or UT) of all pressure-containing parts, (2) 100% magnetic particle or liquid penetrant testing of all accessible surfaces, (3) full material traceability, (4) third-party inspection, (5) gas testing. PSL 4 is the highest quality level.",55),
  tf(2,"The 'wellhead completion riser' used during offshore well completion operations is a permanent installation.",false,"The completion riser is a TEMPORARY installation used during well completion operations to provide a conduit for running tubing, installing the Christmas tree, and performing completion tests. It is removed after completion and replaced by the permanent production riser or flowline.",56),
  tf(2,"In wellhead design, the 'fatigue life' calculation is required only for offshore wells subject to wave loading.",false,"Fatigue analysis is required for: (1) offshore wells (wave, current loads), (2) wells subject to slug flow (pressure pulsations), (3) wells near vibrating equipment, (4) wells with cyclic thermal loading (steam injection, geothermal), (5) any application with cyclic loading. Not limited to offshore.",57),
  tf(2,"The 'wellhead Christmas tree' must be pressure tested with the same fluid that will be produced from the well.",false,"Pressure testing uses water (hydrostatic test) or gas (pneumatic test) - NOT the produced fluid. Water is preferred for safety (lower stored energy than gas). The test verifies mechanical integrity, not compatibility with produced fluids.",58),
  tf(2,"In a wellhead with a 'tubing head adapter' (THA), the THA allows the Christmas tree to be connected to a wellhead with a different flange size or pressure rating.",true,"The THA (also called a tree adapter or crossover spool) adapts between different flange sizes, pressure ratings, or connection types. Allows using a higher-rated tree on a lower-rated wellhead, or connecting different manufacturer's equipment.",59),
  tf(2,"The 'wellhead Christmas tree' swab valve must be rated for the full wellhead working pressure.",true,"All Christmas tree valves, including the swab valve, must be rated for the full wellhead working pressure. The swab valve is in the primary pressure-containing bore and must withstand full wellbore pressure. Using an underrated swab valve is a safety violation.",60),
  tf(2,"In wellhead operations, 'gas lift' injection is always performed through the production tubing.",false,"Gas lift injection can be through: (1) tubing-casing annulus (most common - gas injected into annulus, enters tubing through gas lift valves), (2) tubing (for some completion designs), (3) dedicated gas lift mandrels. The most common configuration injects gas into the annulus.",61),
  tf(2,"The 'wellhead Christmas tree' for a sour service well must have all internal surfaces coated with corrosion-resistant coating.",false,"Sour service wellheads use NACE MR0175-compliant BASE MATERIALS (controlled hardness, specific alloys) - NOT coatings. Coatings can fail and expose the base metal to H2S. Material selection (not coating) is the correct approach for sour service.",62),
  tf(2,"The 'wellhead pressure rating' is determined by the weakest component in the wellhead assembly.",true,"The wellhead system pressure rating = the lowest-rated component in the assembly. If a 5K-rated component is installed in a 10K wellhead, the system is limited to 5K. All components must be rated at or above the required system pressure rating.",63),
  tf(2,"In wellhead design, 'thermal cycling' can cause fatigue failure of ring joint gaskets.",true,"Thermal cycling causes: (1) differential thermal expansion between ring and flange (different materials/temperatures), (2) cyclic stress in the ring, (3) potential fatigue cracking of the ring, (4) loss of seating stress. More critical for HPHT wells with large temperature swings.",64),
  tf(2,"The 'wellhead Christmas tree' kill wing valve is always on the same side as the production wing valve.",false,"The kill wing valve is on the OPPOSITE side from the production wing valve in a standard Christmas tree configuration. This allows simultaneous access to both the production flowline and the kill line without interference.",65),
  tf(2,"In wellhead integrity management, a 'zero-leakage' policy means that any detectable leakage from wellhead equipment requires immediate shutdown.",false,"Zero-leakage policy means no leakage is acceptable as a long-term condition. However, the response to detected leakage depends on: (1) leak location (external vs internal), (2) leak rate, (3) fluid type (H2S, flammable), (4) risk assessment. Not all leaks require immediate shutdown, but all require investigation and remediation.",66),
  tf(2,"The 'wellhead Christmas tree' can be used as a structural support for the production flowline.",false,"The Christmas tree is NOT designed as a structural support for the flowline. Flowlines must be independently supported. Flowline loads (weight, thermal expansion, slug flow forces) must not be transmitted to the wellhead, as they can damage seals and cause fatigue.",67),
  tf(2,"In API 6A, the 'bore' of a wellhead component refers to the internal diameter of the pressure-containing flow path.",true,"Bore = internal diameter of the flow path through the wellhead component. Bore size determines: (1) maximum tubing/casing size that can pass through, (2) flow area, (3) wireline/coiled tubing access. API 6A specifies standard bore sizes for each pressure class.",68),
  tf(2,"The 'wellhead Christmas tree' must be function-tested at the wellsite before installation on the well.",true,"Pre-installation function testing (stump test or FAT): (1) verifies all valves open and close correctly, (2) pressure tests all seals, (3) tests actuators and control systems, (4) verifies dimensional compatibility with wellhead. Identifies problems before costly offshore installation.",69),
  tf(2,"In wellhead design, the 'corrosion allowance' for sour service wells is always 3mm.",false,"Corrosion allowance depends on: (1) corrosion rate (from material selection, inhibitor effectiveness, fluid composition), (2) design life, (3) inspection frequency. CA = corrosion rate × design life. For NACE-compliant materials in properly inhibited systems, CA may be 1-3mm. Not a fixed value.",70),
];

// ============================================================
// MAIN SEEDING FUNCTION
// ============================================================
async function main() {
  const conn = await mysql.createConnection(process.env.DATABASE_URL);
  console.log('Connected to database');

  let addedModule = 0, skippedModule = 0;
  let addedExam = 0, skippedExam = 0;

  // ── 1. Seed module questions (10 per module) ──────────────
  for (const q of moduleQuestions) {
    // Check if question already exists (by module + order)
    const [existing] = await conn.execute(
      'SELECT id FROM quiz_questions WHERE module_id = ? AND `order` = ?',
      [q.moduleId, q.order]
    );
    if (existing.length > 0) {
      skippedModule++;
      continue;
    }
    await conn.execute(
      `INSERT INTO quiz_questions (module_id, question_text_en, question_text_ar, options_json, correct_option_id, explanation_en, explanation_ar, \`order\`, created_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, NOW())`,
      [
        q.moduleId,
        q.questionTextEn,
        q.questionTextEn,
        JSON.stringify(q.options),
        q.correctOptionId,
        q.explanationEn,
        q.explanationEn,
        q.order
      ]
    );
    addedModule++;
  }
  console.log(`Module questions: ${addedModule} added, ${skippedModule} skipped`);

  // ── 2. Seed course final exam questions ───────────────────
  const allExamQuestions = [...epfFinalQuestions, ...wellheadFinalQuestions];
  for (const q of allExamQuestions) {
    const [existing] = await conn.execute(
      'SELECT id FROM course_exam_questions WHERE course_id = ? AND `order` = ?',
      [q.courseId, q.order]
    );
    if (existing.length > 0) {
      skippedExam++;
      continue;
    }
    await conn.execute(
      `INSERT INTO course_exam_questions (course_id, question_type, question_text_en, question_text_ar, options, correct_option_id, explanation_en, explanation_ar, difficulty, time_limit_seconds, \`order\`, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())`,
      [
        q.courseId,
        q.questionType,
        q.questionTextEn,
        q.questionTextEn,
        JSON.stringify(q.options),
        q.correctOptionId,
        q.explanationEn,
        q.explanationEn,
        q.difficulty,
        q.timeLimitSeconds,
        q.order
      ]
    );
    addedExam++;
  }
  console.log(`Exam questions: ${addedExam} added, ${skippedExam} skipped`);

  await conn.end();
  console.log('Done!');
}

main().catch(console.error);
